CREATE OR REPLACE PROCEDURE run_fraud_detection_sweep(
  p_detection_date DATE,
  p_sensitivity     VARCHAR2 DEFAULT 'medium'
) AS
  v_velocity_limit  NUMBER;
  v_amount_limit    NUMBER;
  v_rule_version    VARCHAR2(20);
  TYPE t_txn_rec IS RECORD (
    account_id   NUMBER,
    txn_count    NUMBER,
    total_amount NUMBER,
    max_single   NUMBER
  );
  TYPE t_txn_tab IS TABLE OF t_txn_rec;
  v_suspicious t_txn_tab;
  v_case_id    NUMBER;
BEGIN
  SELECT velocity_limit, amount_limit, rule_version
  INTO v_velocity_limit, v_amount_limit, v_rule_version
  FROM fraud_detection_rules
  WHERE sensitivity = p_sensitivity AND active_flag = 'Y'
  AND ROWNUM = 1
  ORDER BY created_at DESC;

  SELECT account_id, COUNT(*), SUM(txn_amount), MAX(txn_amount)
  BULK COLLECT INTO v_suspicious
  FROM payment_transactions
  WHERE txn_date = p_detection_date AND flagged = 'N'
  GROUP BY account_id
  HAVING COUNT(*) > v_velocity_limit OR MAX(txn_amount) > v_amount_limit;

  SELECT NVL(MAX(case_id),0)+1 INTO v_case_id FROM fraud_cases;

  FORALL i IN 1..v_suspicious.COUNT
    INSERT INTO fraud_cases
      (case_id, account_id, detection_date, txn_count,
       total_amount, max_single_txn, sensitivity, rule_version,
       case_status, opened_at)
    VALUES
      (v_case_id + i - 1, v_suspicious(i).account_id, p_detection_date,
       v_suspicious(i).txn_count, v_suspicious(i).total_amount,
       v_suspicious(i).max_single, p_sensitivity, v_rule_version,
       'open', SYSDATE);

  FORALL i IN 1..v_suspicious.COUNT
    UPDATE payment_transactions
    SET flagged = 'Y', fraud_case_ref = v_case_id + i - 1
    WHERE account_id = v_suspicious(i).account_id
    AND txn_date     = p_detection_date;

  INSERT INTO fraud_sweep_log
    (detection_date, sensitivity, rule_version, cases_opened, run_at)
  VALUES (p_detection_date, p_sensitivity, v_rule_version, v_suspicious.COUNT, SYSDATE);
  COMMIT;
EXCEPTION
  WHEN NO_DATA_FOUND THEN
    INSERT INTO fraud_sweep_log
      (detection_date, sensitivity, rule_version, cases_opened, error_msg, run_at)
    VALUES (p_detection_date, p_sensitivity, NULL, 0, 'No active rule found', SYSDATE);
    COMMIT;
END;

DECLARE
  CURSOR emp_cursor IS
    SELECT first_name, last_name, job_id, salary
    FROM employees;

  TYPE emp_type IS TABLE OF emp_cursor%ROWTYPE;
  v_emp emp_type;

BEGIN
  -- Open the cursor and fetch all rows into a collection
  OPEN emp_cursor;
  LOOP
    FETCH emp_cursor BULK COLLECT INTO v_emp LIMIT 100; -- Fetch up to 100 rows at a time
    EXIT WHEN v_emp.COUNT = 0;

    -- Process each row in the collection
    FOR i IN 1..v_emp.COUNT LOOP
      DBMS_OUTPUT.PUT_LINE('Employee: ' || v_emp(i).first_name || ' ' || v_emp(i).last_name);
    END LOOP;
  END LOOP;

  -- Close the cursor
  CLOSE emp_cursor;

EXCEPTION
  WHEN OTHERS THEN
    DBMS_OUTPUT.PUT_LINE('An error occurred: ' || SQLERRM);
END;
/

CREATE PROCEDURE usp_ComplexDataPivotReport
    @Year INT
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @cols    NVARCHAR(MAX);
    DECLARE @sql     NVARCHAR(MAX);

    SELECT @cols = STRING_AGG(
        QUOTENAME(DATENAME(MONTH, DATEFROMPARTS(@Year, month_num, 1))),
        ', '
    ) WITHIN GROUP (ORDER BY month_num)
    FROM (
        SELECT DISTINCT MONTH(sale_date) AS month_num
        FROM dbo.sales
        WHERE YEAR(sale_date) = @Year
    ) m;

    SET @sql = N'
        SELECT store_id, product_id,
               DATENAME(MONTH, sale_date) AS sale_month,
               SUM(quantity * unit_price)  AS revenue
            FROM dbo.sales
            WHERE YEAR(sale_date) = ' + CAST(@Year AS NVARCHAR) + N'
            GROUP BY store_id, product_id, DATENAME(MONTH, sale_date)
        ) src;

    -- Create a temp table to hold the pivot data
    CREATE TABLE #PivotData (
        store_id INT,
        product_id INT,
        revenue DECIMAL(10, 2),
        sale_month NVARCHAR(MAX)
    );

    -- Insert the pivot data into the temp table
    INSERT INTO #PivotData (store_id, product_id, revenue, sale_month)
    SELECT store_id, product_id, revenue, sale_month
    FROM src;

    -- Pivot the data using a MERGE statement
    MERGE INTO dbo.PivotedSalesReport AS target
    USING #PivotData AS source
    ON target.store_id = source.store_id AND target.product_id = source.product_id
    WHEN MATCHED THEN
        UPDATE SET target.revenue = source.revenue
    WHEN NOT MATCHED BY TARGET THEN
        INSERT (store_id, product_id, revenue, sale_month)
        VALUES (source.store_id, source.product_id, source.revenue, source.sale_month);

    -- Clean up the temp table
    DROP TABLE #PivotData;

    EXEC sp_executesql @sql;
END;

CREATE PROCEDURE InsertOrUpdateCustomerOrders (@CustomerID INT, @OrderDetails NVARCHAR(MAX), @IsSuccess BIT OUTPUT)
AS
BEGIN
    DECLARE @OrderId INT;
    DECLARE @Error VARCHAR(1024);

    BEGIN TRY
        -- Attempt to insert or update the order details in the Orders table
        MERGE INTO Orders AS T
        USING (VALUES (@CustomerID, @OrderDetails)) AS S (CustomerID, OrderDetails)
        ON T.CustomerID = S.CustomerID

        WHEN MATCHED THEN
            UPDATE SET T.OrderDetails = S.OrderDetails

        WHEN NOT MATCHED BY TARGET THEN
            INSERT (CustomerID, OrderDetails) VALUES (S.CustomerID, S.OrderDetails);

        SET @OrderId = SCOPE_IDENTITY();
    END TRY

    BEGIN CATCH
        -- Handle any errors that occur during the MERGE operation
        SET @Error = ERROR_MESSAGE();
        SET @IsSuccess = 0;
    END CATCH;

    RETURN @OrderId;
END

CREATE PROCEDURE GenerateCustomerOrders
    @CustomerID INT,
    @OrderDate DATETIME,
    @TotalAmount DECIMAL(18,2) OUTPUT,
    @ProductsToShip INT OUTPUT,
    @ShippedCount INT OUTPUT,
    @ShipmentCost DECIMAL(18,2) OUTPUT
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @AvailableOrders DECIMAL(18,2);

    BEGIN TRY
        SELECT @AvailableOrders = SUM(TotalAmount)
        FROM Orders
        WHERE CustomerID = @CustomerID AND OrderDate < GETDATE();
    END TRY

    BEGIN CATCH
        SET @AvailableOrders = 0;
    END CATCH;

    CREATE TABLE #OrderDetails (
        OrderID INT,
        ProductID INT,
        Quantity INT,
        UnitPrice DECIMAL(18,2),
        TotalAmount DECIMAL(18,2)
    );

    MERGE INTO Orders o
    USING (SELECT * FROM #OrderDetails) od ON o.OrderID = od.OrderID AND o.CustomerID = od.CustomerID
    WHEN MATCHED THEN
        UPDATE SET o.Quantity = od.Quantity,
                    o.TotalAmount = od.TotalAmount
    WHEN NOT MATCHED BY TARGET THEN
        INSERT (
            OrderID, CustomerID, OrderDate, Quantity, UnitPrice, TotalAmount
        )
        VALUES (
            od.OrderID, od.CustomerID, od.OrderDate, od.Quantity, od.UnitPrice, od.TotalAmount
        );

    SELECT
        @TotalAmount = ISNULL(SUM(TotalAmount), 0),
        @ProductsToShip = COUNT(OrderID),
        @ShippedCount = SUM(CASE WHEN o.ShippedDate IS NOT NULL THEN 1 ELSE 0 END)
    FROM Orders o
    WHERE o.CustomerID = @CustomerID;

    SELECT @ShipmentCost = ISNULL(SUM(od.TotalAmount), 0) * 0.10 AS ShipmentCost
    FROM Orders o
    JOIN #OrderDetails od ON o.OrderID = od.OrderID AND o.CustomerID = od.CustomerID
    WHERE o.ShippedDate IS NOT NULL;

    SELECT * FROM #OrderDetails ORDER BY Quantity DESC, TotalAmount DESC;

    DROP TABLE #OrderDetails;
END

