DECLARE
    v_employee_id NUMBER := 101;
    v_performance_score NUMBER := 85;
    v_base_salary NUMBER;
    v_bonus_rate NUMBER;
    v_bonus_amount NUMBER;
BEGIN
    -- CURSOR to fetch employee details
    DECLARE
        CURSOR emp_cur IS
            SELECT salary
            FROM employees
            WHERE employee_id = v_employee_id;

        v_emp_rec emp_cur%ROWTYPE;
    BEGIN
        OPEN emp_cur;
        FETCH emp_cur INTO v_emp_rec;
        CLOSE emp_cur;

        -- BULK COLLECT to fetch all performance scores for the employee
        DECLARE
            CURSOR perf_cur IS
                SELECT performance_score
                FROM employees
                WHERE employee_id = v_employee_id;

            v_perf_scores emp_cur%ROWTYPE;
            v_perf_scores_array NUMBER := 0;
            v_perf_scores_list NUMBER := 0;
        BEGIN
            OPEN perf_cur;
            LOOP
                FETCH perf_cur INTO v_perf_scores;
                EXIT WHEN perf_cur%NOTFOUND;
                DBMS_OUTPUT.PUT_LINE('Performance Score: ' || v_perf_scores);
                v_perf_scores_array := v_perf_scores_array + 1;
                v_perf_scores_list := v_perf_scores_list + v_perf_scores;
            END LOOP;
            CLOSE perf_cur;

            -- EXCEPTION handling
            BEGIN
                IF v_perf_scores_array > 0 THEN
                    -- Calculate bonus based on the average performance score
                    v_bonus_rate := SUM(v_perf_scores_list) / v_perf_scores_array;
                    v_bonus_amount := v_emp_rec.salary * v_bonus_rate;
                    DBMS_OUTPUT.PUT_LINE('Bonus Amount: ' || v_bonus_amount);
                ELSE
                    DBMS_OUTPUT.PUT_LINE('No performance scores found.');
                END IF;
            EXCEPTION
                WHEN NO_DATA_FOUND THEN
                    DBMS_OUTPUT.PUT_LINE('Employee not found.');
                WHEN OTHERS THEN
                    DBMS_OUTPUT.PUT_LINE('Error occurred: ' || SQLERRM);
            END;

            -- DBMS_OUTPUT to log results
            DBMS_OUTPUT.PUT_LINE('Base Salary: ' || v_emp_rec.salary);
            DBMS_OUTPUT.PUT_LINE('Bonus Rate: ' || v_bonus_rate);
            DBMS_OUTPUT.PUT_LINE('Bonus Amount: ' || v_bonus_amount);
        END;
    END;
END;
/

