from pyspark.sql import SparkSession

spark = SparkSession.builder.appName('EmployeeBonusCalculation').getOrCreate()

# Function to calculate bonus based on performance score
def calculate_employee_bonus(salary, performance_score):
    if salary is None:
        return 0.0
    if performance_score >= 90:
        bonus_rate = 0.20
    elif performance_score >= 75:
        bonus_rate = 0.15
    elif performance_score >= 60:
        bonus_rate = 0.10
    else:
        bonus_rate = 0.05
    return float(salary * bonus_rate)

# DataFrame to simulate employee data
employees_df = spark.createDataFrame([
    (101, 'John Doe', 85),
    (102, 'Jane Smith', 78)
], ['employee_id', 'name', 'performance_score'])

# Apply the bonus calculation using UDF
bonus_udf = udf(calculate_employee_bonus, DoubleType())

# Calculate bonuses for each employee
result_df = employees_df.withColumn('bonus_amount', bonus_udf(col('salary'), col('performance_score')))

result_df.select('employee_id', 'name', 'performance_score', 'bonus_rate', 'bonus_amount').show()

