CREATE PROCEDURE GetOrderDetails
    @OrderID INT,
    @CustomerName NVARCHAR(100),
    @OrderDate DATETIME,
    @TotalAmount DECIMAL(18,2) OUT,
    @Status NVARCHAR(50) OUT,
    @ErrorMsg NVARCHAR(MAX) OUTPUT
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @OrderDetails TABLE (
        OrderID INT PRIMARY KEY,
        CustomerName NVARCHAR(100),
        OrderDate DATETIME,
        TotalAmount DECIMAL(18,2)
    );

    BEGIN TRY
        -- Fetch order details from the Orders table
        INSERT INTO @OrderDetails (OrderID, CustomerName, OrderDate, TotalAmount)
        SELECT OrderID, CustomerName, OrderDate, TotalAmount
        FROM Orders
        WHERE OrderID = @OrderID;

        -- Update the status of the order in the Orders table
        UPDATE Orders
        SET Status = 'Processed'
        WHERE OrderID = @OrderID;

        -- Fetch updated order details from the temporary table
        SELECT @TotalAmount = TotalAmount,
               @Status = Status
        FROM @OrderDetails
        WHERE OrderID = @OrderID;
    END TRY
    BEGIN CATCH
        SET @ErrorMsg = ERROR_MESSAGE();
    END CATCH

    RETURN;
END

CREATE OR REPLACE PACKAGE audit_pkg AS
  PROCEDURE log_change(
    p_table_name IN VARCHAR2,
    p_operation  IN VARCHAR2,
    p_row_id     IN VARCHAR2,
    p_old_val    IN CLOB DEFAULT NULL,
    p_new_val    IN CLOB DEFAULT NULL
  );
  FUNCTION get_audit_trail(
    p_table_name IN VARCHAR2,
    p_from_date  IN DATE
  ) RETURN SYS_REFCURSOR;
END audit_pkg;
/
CREATE OR REPLACE PACKAGE BODY audit_pkg AS
  PROCEDURE log_change(p_table_name IN VARCHAR2, p_operation IN VARCHAR2,
                       p_row_id IN VARCHAR2, p_old_val IN CLOB DEFAULT NULL,
                       p_new_val IN CLOB DEFAULT NULL) IS
    PRAGMA AUTONOMOUS_TRANSACTION;
  BEGIN
    INSERT INTO audit_log(table_name, operation, row_id, old_value, new_value, changed_at, changed_by)
    VALUES (p_table_name, p_operation, p_row_id, p_old_val, p_new_val, SYSTIMESTAMP, SYS_CONTEXT('USERENV','SESSION_USER'));
    COMMIT;
  EXCEPTION
    WHEN OTHERS THEN NULL;
  END;

  FUNCTION get_audit_trail(p_table_name IN VARCHAR2, p_from_date IN DATE)
  RETURN SYS_REFCURSOR AS
    v_cur SYS_REFCURSOR;
  BEGIN
    OPEN v_cur FOR
      SELECT * FROM audit_log
      WHERE table_name = p_table_name
        AND TRUNC(changed_at) >= p_from_date
      ORDER BY changed_at;
    RETURN v_cur;
  END;
END audit_pkg;

