CREATE PROCEDURE GetCustomerDetails
    @CustomerID INT,
    @FirstName NVARCHAR(50) OUTPUT,
    @LastName NVARCHAR(50) OUTPUT,
    @Email NVARCHAR(100) OUTPUT,
    @Phone NVARCHAR(20) OUTPUT,
    @Address NVARCHAR(255) OUTPUT,
    @City NVARCHAR(50) OUTPUT,
    @State NVARCHAR(20) OUTPUT,
    @ZipCode NVARCHAR(10) OUTPUT
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @CustomerDetails TABLE (
        CustomerID INT,
        FirstName NVARCHAR(50),
        LastName NVARCHAR(50),
        Email NVARCHAR(100),
        Phone NVARCHAR(20),
        Address NVARCHAR(255),
        City NVARCHAR(50),
        State NVARCHAR(20),
        ZipCode NVARCHAR(10)
    );

    DECLARE @CustomerData TABLE (
        CustomerID INT,
        FirstName NVARCHAR(50),
        LastName NVARCHAR(50),
        Email NVARCHAR(100),
        Phone NVARCHAR(20),
        Address NVARCHAR(255),
        City NVARCHAR(50),
        State NVARCHAR(20),
        ZipCode NVARCHAR(10)
    );

    BEGIN TRY
        INSERT INTO @CustomerData (CustomerID, FirstName, LastName, Email, Phone, Address, City, State, ZipCode)
        SELECT CustomerID, FirstName, LastName, Email, Phone, Address, City, State, ZipCode
        FROM Customers
        WHERE CustomerID = @CustomerID;

        IF @@ROWCOUNT = 0
        BEGIN
            INSERT INTO @CustomerData (CustomerID, FirstName, LastName, Email, Phone, Address, City, State, ZipCode)
            SELECT CustomerID, FirstName, LastName, Email, Phone, Address, City, State, ZipCode
            FROM Customers
            WHERE CustomerID IN (SELECT CustomerID FROM Orders WHERE CustomerID = @CustomerID);
        END

        INSERT INTO @CustomerDetails (CustomerID, FirstName, LastName, Email, Phone, Address, City, State, ZipCode)
        SELECT * FROM @CustomerData;
    END TRY
    BEGIN CATCH
        DECLARE @ErrorMessage NVARCHAR(MAX) = ERROR_MESSAGE();
        SET @FirstName = NULL;
        SET @LastName = NULL;
        SET @Email = NULL;
        SET @Phone = NULL;
        SET @Address = NULL;
        SET @City = NULL;
        SET @State = NULL;
        SET @ZipCode = NULL;

        IF @@ROWCOUNT > 0
        BEGIN
