CREATE PROCEDURE UpdateCustomerStatus
AS
BEGIN
    DECLARE @CustomerID INT;
    DECLARE @NewStatus NVARCHAR(50);

    -- Open a cursor to iterate over customers
    OPEN CustomerCursor;

    FETCH NEXT FROM CustomerCursor INTO @CustomerID, @NewStatus;

    WHILE @@FETCH_STATUS = 0
    BEGIN
        TRY
            -- Update the customer status using MERGE statement
            UPDATE Customers
            SET Status = @NewStatus
            WHERE CustomerID = @CustomerID;
        EXCEPT
            -- Handle exception for duplicate key or other errors
            RAISERROR('Error updating customer status', 16, 1);
        END TRY

        FETCH NEXT FROM CustomerCursor INTO @CustomerID, @NewStatus;
    END WHILE;

    CLOSE CustomerCursor;
    DEALLOCATE CustomerCursor;
END

