CREATE PROCEDURE MergeOrderDetails (
    @OrderId INT,
    @CustomerID INT,
    @ProductName NVARCHAR(100),
    @Quantity INT,
    @Price DECIMAL(10, 2)
)
AS
BEGIN
    -- Start a transaction
    BEGIN TRANSACTION;

    -- Try to insert the new order details into the target table
    BEGIN TRY
        INSERT INTO Orders (OrderID, CustomerID, ProductName, Quantity, Price)
        VALUES (@OrderId, @CustomerID, @ProductName, @Quantity, @Price);

        -- Insert the related order detail into the temporary table
        INSERT INTO #MergedOrders (OrderID, CustomerID, ProductName, Quantity, Price)
        VALUES (@OrderId, @CustomerID, @ProductName, @Quantity, @Price);
    END TRY

    BEGIN CATCH
        -- Rollback the transaction in case of an error
        ROLLBACK TRANSACTION;

        -- Raise an exception with the error message
        DECLARE @ErrorMessage NVARCHAR(4000);
        SELECT @ErrorMessage = ERROR_MESSAGE();
        RAISERROR('An error occurred while processing the order details: %s', 16, 1, @ErrorMessage);
    END CATCH

    -- Commit the transaction if no errors occur
    COMMIT TRANSACTION;
END;

