        END LOOP;
        CLOSE c_employees;

        p_it_payroll := v_it_payroll;
        p_sales_payroll := v_sales_payroll;
        p_total_payroll := v_it_payroll + v_sales_payroll;
    EXCEPTION
        WHEN OTHERS THEN
