CREATE PROCEDURE GetCustomerOrders
    @CustomerId INT,
    @StartDate DATE,
    @EndDate DATE,
    @TotalOrderAmount DECIMAL(18,2) OUTPUT,
    @OrderCount INT OUTPUT,
    @AvgOrderSize DECIMAL(18,2) OUTPUT,
    @PerformanceTier NVARCHAR(20) OUTPUT,
    @BonusEligible BIT OUTPUT
AS
BEGIN
    SET NOCOUNT ON;

    -- Create a temporary table to hold the filtered orders
    DECLARE @OrdersTemp TABLE (
        OrderID INT PRIMARY KEY,
        CustomerID INT,
        OrderDate DATE,
        OrderAmount DECIMAL(18,2)
    );

    -- Insert data into the temp table based on the provided date range and customer ID
    INSERT INTO @OrdersTemp
    SELECT O.OrderID, O.CustomerID, O.OrderDate, O.OrderAmount
    FROM Orders O
    WHERE O.CustomerID = @CustomerId
      AND O.OrderDate BETWEEN @StartDate AND @EndDate;

    -- Calculate total order amount and count of orders
    DECLARE @TotalOrderAmount DECIMAL(18,2);
    DECLARE @OrderCount INT;

    SELECT @TotalOrderAmount = SUM(OA.OrderAmount), @OrderCount = COUNT(OA.OrderID)
    FROM @OrdersTemp OA;

    -- Calculate average order size if there are orders, otherwise set to 0
    IF @OrderCount > 0
        SET @AvgOrderSize = @TotalOrderAmount / @OrderCount;
    ELSE
        SET @AvgOrderSize = 0;

    -- Determine performance tier and bonus eligibility based on the total order amount
    DECLARE @QuotaTarget DECIMAL(18,2);
    SELECT @QuotaTarget = q.QuotaAmount
    FROM Quotas q
    WHERE q.CustomerID = @CustomerId
      AND q.QuotaYear = YEAR(@StartDate);

    IF @QuotaTarget IS NULL OR @QuotaTarget = 0
        SET @PerformanceTier = 'NEEDS_IMPROVEMENT';
        SET @BonusEligible = 0;
    ELSE
        SET @PerformanceTier = CASE 
            WHEN (@TotalOrderAmount / @QuotaTarget) * 100 >= 120 THEN 'ELITE'
            WHEN (@TotalOrderAmount / @QuotaTarget) * 100 >= 100 THEN 'ACHIEVER'
            WHEN (@TotalOrderAmount / @QuotaTarget) * 100 >= 80 THEN 'CONTRIBUTOR'
            ELSE 'NEEDS_IMPROVEMENT'
        END;
    END

    -- Output the results
    SELECT 
        @TotalOrderAmount AS TotalOrderAmount,
        @OrderCount AS OrderCount,
        @AvgOrderSize AS AvgOrderSize,
        @PerformanceTier AS PerformanceTier,
        @BonusEligible AS BonusEligible;

END

CREATE PROCEDURE usp_MergeCustomerOrders
    @CustomerId INT,
    @NewOrderID INT,
    @NewProductID INT,
    @NewQuantity INT,
    @EffectiveDate DATE = NULL
AS
BEGIN
    SET NOCOUNT ON;
    SET @EffectiveDate = ISNULL(@EffectiveDate, CAST(GETDATE() AS DATE));

    BEGIN TRANSACTION;
    BEGIN TRY
        -- Step 1: Create temp table to hold new orders
        CREATE TABLE #temp_orders (
            OrderID INT,
            ProductID INT,
            Quantity INT,
            EffectiveDate DATE
        );

        -- Insert new order into temp table
        INSERT INTO #temp_orders (OrderID, ProductID, Quantity, EffectiveDate)
        VALUES (@NewOrderID, @NewProductID, @NewQuantity, @EffectiveDate);

        -- Step 2: Perform MERGE operation on Orders table
        MERGE INTO Orders AS T1
        USING #temp_orders AS T2
        ON T1.CustomerID = T2.CustomerID AND T1.OrderID = T2.OrderID AND T1.ProductID = T2.ProductID
        WHEN MATCHED THEN
            UPDATE SET T1.Quantity = T2.Quantity, T1.EffectiveDate = T2.EffectiveDate
        WHEN NOT MATCHED BY TARGET THEN
            INSERT (CustomerID, OrderID, ProductID, Quantity, EffectiveDate)
            VALUES (T2.CustomerID, T2.OrderID, T2.ProductID, T2.Quantity, T2.EffectiveDate);

        -- Step 3: Clean up temp table
        DROP TABLE #temp_orders;

        COMMIT TRANSACTION;
    END TRY
    BEGIN CATCH
        ROLLBACK TRANSACTION;
        INSERT INTO ErrorLog (ProcedureName, ErrorMessage, ErrorTime)
