CREATE PROCEDURE GetCustomerPurchaseHistoryWithOutput
    @CustomerID INT,
    @TotalAmount DECIMAL(10, 2) OUTPUT
AS
BEGIN
    DECLARE @OrderID INT;
    DECLARE @OrderDate DATETIME;
    DECLARE @TotalAmount DECIMAL(10, 2);

    BEGIN TRY
        -- Create a temporary table to store the order details
        CREATE TEMPORARY TABLE #CustomerOrders (
            OrderID INT,
            OrderDate DATETIME,
            TotalAmount DECIMAL(10, 2)
        );

        -- Insert data into the temporary table based on the customer ID
        INSERT INTO #CustomerOrders (OrderID, OrderDate, TotalAmount)
        SELECT o.OrderID, o.OrderDate, o.TotalAmount
        FROM Orders o
        WHERE o.CustomerID = @CustomerID;

        -- Use a cursor to iterate through the orders and calculate total amount
        DECLARE cur CURSOR FOR SELECT * FROM #CustomerOrders;
        DECLARE @OrderID INT, @OrderDate DATETIME, @TotalAmount DECIMAL(10, 2);

        OPEN cur;
        FETCH NEXT FROM cur INTO @OrderID, @OrderDate, @TotalAmount;

        WHILE @@FETCH_STATUS = 0
        BEGIN
            -- Calculate the total amount for each order
            SET @TotalAmount = @TotalAmount + @TotalAmount;

            -- Update the temporary table with the calculated total amount
            UPDATE #CustomerOrders
            SET TotalAmount = @TotalAmount
            WHERE OrderID = @OrderID;

            FETCH NEXT FROM cur INTO @OrderID, @OrderDate, @TotalAmount;
        END;

        CLOSE cur;
        DEALLOCATE cur;

        -- Set the output parameter with the total amount
        SET @TotalAmount = (SELECT TotalAmount FROM #CustomerOrders);

        -- Drop the temporary table after use
        DROP TABLE #CustomerOrders;
    END TRY

    BEGIN CATCH
        DECLARE @ErrorMessage NVARCHAR(MAX);
        SELECT @ErrorMessage = ERROR_MESSAGE();

        RAISERROR (@ErrorMessage, 16, 1);
    END CATCH;
END

CREATE PROCEDURE usp_DynamicPivotSalesReport
    @Year INT
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @cols    NVARCHAR(MAX);
    DECLARE @sql     NVARCHAR(MAX);

    SELECT @cols = STRING_AGG(
        QUOTENAME(DATENAME(MONTH, DATEFROMPARTS(@Year, month_num, 1))),
        ', '
    ) WITHIN GROUP (ORDER BY month_num)
    FROM (
        SELECT DISTINCT MONTH(sale_date) AS month_num
        FROM dbo.sales
        WHERE YEAR(sale_date) = @Year
    ) m;

    SET @sql = N'
        SELECT store_id, product_id, ' + @cols + N'
        FROM (
            SELECT store_id, product_id,
                   DATENAME(MONTH, sale_date) AS sale_month,
                   SUM(quantity * unit_price)  AS revenue
            FROM dbo.sales
            WHERE YEAR(sale_date) = ' + CAST(@Year AS NVARCHAR) + N'
            GROUP BY store_id, product_id, DATENAME(MONTH, sale_date)
        ) src
        PIVOT (
            SUM(revenue)
            FOR sale_month IN (' + @cols + N')
        ) pvt
        ORDER BY store_id, product_id;';

    EXEC sp_executesql @sql;
END;

CREATE PROCEDURE usp_ProcessEmployeeBonuses
    @FiscalYear INT
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @dept_id   INT;
    DECLARE @dept_name VARCHAR(100);
    DECLARE @avg_perf  DECIMAL(5,2);

    DECLARE dept_cursor CURSOR FAST_FORWARD FOR
        SELECT department_id, department_name
        FROM   hr.departments
        WHERE  active = 1;

    OPEN dept_cursor;
    FETCH NEXT FROM dept_cursor INTO @dept_id, @dept_name;

    WHILE @@FETCH_STATUS = 0
    BEGIN
        SELECT @avg_perf = AVG(performance_score)
        FROM   hr.performance_reviews
        WHERE  department_id = @dept_id
          AND  fiscal_year   = @FiscalYear;

        UPDATE hr.employees
        SET    bonus_amount = CASE
                   WHEN performance_score >= @avg_perf * 1.2 THEN salary * 0.15
                   WHEN performance_score >= @avg_perf        THEN salary * 0.10
                   ELSE salary * 0.05
               END,
               bonus_year   = @FiscalYear
        WHERE  department_id = @dept_id
          AND  fiscal_year   = @FiscalYear;

        FETCH NEXT FROM dept_cursor INTO @dept_id, @dept_name;
    END;

    CLOSE dept_cursor;
    DEALLOCATE dept_cursor;
END;

