CREATE OR REPLACE PROCEDURE calculate_employee_bonus(
    p_employee_id IN NUMBER,
    p_performance_score IN NUMBER
) IS
    v_base_salary    NUMBER;
    v_bonus_rate     NUMBER;
    v_bonus_amount   NUMBER;
BEGIN
    -- CURSOR to fetch employee details
    DECLARE
        cursor employee_cursor IS
            SELECT salary FROM employees WHERE employee_id = p_employee_id;

        v_employee_record employee_cursor%ROWTYPE;
    BEGIN
        -- OPEN the cursor
        OPEN employee_cursor;

        -- FETCH data into a collection
        LOOP
            FETCH employee_cursor INTO v_employee_record;
            EXIT WHEN employee_cursor%NOTFOUND;

            -- EXCEPTION handling for missing data
            BEGIN
                SELECT salary INTO v_base_salary
                FROM employees
                WHERE employee_id = p_employee_id;

                IF p_performance_score >= 90 THEN
                    v_bonus_rate := 0.20;
                ELSIF p_performance_score >= 75 THEN
                    v_bonus_rate := 0.15;
                ELSIF p_performance_score >= 60 THEN
                    v_bonus_rate := 0.10;
                ELSE
                    v_bonus_rate := 0.05;
                END IF;

                v_bonus_amount := v_base_salary * v_bonus_rate;

                -- DBMS_OUTPUT to log the bonus calculation
                DBMS_OUTPUT.PUT_LINE('Bonus Calculation for Employee ID ' || p_employee_id || ': Base Salary = ' || v_base_salary || ', Performance Score = ' || p_performance_score || ', Bonus Rate = ' || v_bonus_rate || ', Bonus Amount = ' || v_bonus_amount);

                -- RETURN value from the stored procedure
                RETURN v_bonus_amount;
            EXCEPTION
                WHEN NO_DATA_FOUND THEN
                    DBMS_OUTPUT.PUT_LINE('No data found for Employee ID ' || p_employee_id);
                    RETURN 0;
            END;
        END LOOP;

        -- CLOSE the cursor
        CLOSE employee_cursor;
    END calculate_employee_bonus;
/

CREATE PROCEDURE usp_MultiProductSalesReport
    @ProductId INT,
    @StartDate DATE,
    @EndDate DATE
AS
BEGIN
    SET NOCOUNT ON;

    -- Create a temporary table to store intermediate results
    CREATE TABLE #TempSales (
        ProductId INT,
        SaleDate DATE,
        SalesAmount DECIMAL(10, 2)
    );

    -- TRY/CATCH block for error handling
    BEGIN TRY
        -- CURSOR-based loop for data retrieval
        DECLARE cur CURSOR FOR
            SELECT p.ProductId, s.SaleDate, s.SalesAmount
            FROM Products p
            INNER JOIN Orders o ON p.ProductId = o.ProductId
            WHERE o.OrderDate BETWEEN @StartDate AND @EndDate;

        OPEN cur;

        FETCH NEXT FROM cur INTO @ProductId, @SaleDate, @SalesAmount;

        WHILE @@FETCH_STATUS = 0
        BEGIN
            -- Insert the data into the temporary table
            INSERT INTO #TempSales (ProductId, SaleDate, SalesAmount)
            VALUES (@ProductId, @SaleDate, @SalesAmount);

            FETCH NEXT FROM cur INTO @ProductId, @SaleDate, @SalesAmount;
        END;

        CLOSE cur;
        DEALLOCATE cur;

        -- Output the results
        SELECT * FROM #TempSales;
    END TRY
    BEGIN CATCH
        DECLARE @ErrorMessage NVARCHAR(MAX);
        SET @ErrorMessage = ERROR_MESSAGE();

        RAISERROR('An error occurred: %s', 16, 1, @ErrorMessage);
    END CATCH;

    -- Clean up the temporary table
    DROP TABLE #TempSales;
END

