CREATE PROCEDURE UpdateCustomerAddress
    @CustomerID INT,
    @NewAddress NVARCHAR(255),
    @UpdateType NVARCHAR(10)
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @CurrentAddress NVARCHAR(255);

    BEGIN TRY
        -- Fetch the current address from the Customers table
        SELECT @CurrentAddress = Address FROM Customers WHERE CustomerID = @CustomerID;
    END TRY

    BEGIN CATCH
        SET @CurrentAddress = NULL; -- Handle the case where the customer does not exist
    END CATCH

    -- Construct the dynamic SQL statement based on the update type
    DECLARE @DynamicSQL NVARCHAR(MAX);
    IF @UpdateType = 'UPDATE'
        SET @DynamicSQL = N'UPDATE Customers SET Address = @NewAddress WHERE CustomerID = @CustomerID';
    ELSE IF @UpdateType = 'DELETE'
        SET @DynamicSQL = N'DELETE FROM Customers WHERE CustomerID = @CustomerID';
    ELSE
        RAISERROR('Invalid update type', 16, 1);

    -- Execute the dynamic SQL statement
    EXEC sp_executesql @DynamicSQL, N'@NewAddress NVARCHAR(255), @CustomerID INT', @NewAddress, @CustomerID;

    -- Output parameters for success or failure
    DECLARE @Result NVARCHAR(MAX);
    IF @@ROWCOUNT > 0
        SET @Result = 'Update successful';
    ELSE
        SET @Result = 'Update failed';

    SELECT @Result AS Result;
END

DECLARE
  v_xml    XMLTYPE;
  v_doc    DBMS_XMLDOM.DOMDocument;
  v_root   DBMS_XMLDOM.DOMElement;
  v_emp    DBMS_XMLDOM.DOMElement;
  v_node   DBMS_XMLDOM.DOMNode;
  CURSOR c_emp IS
    SELECT employee_id, first_name, last_name, salary, department_id
    FROM   employees
    WHERE  department_id = 10;
BEGIN
  v_doc  := DBMS_XMLDOM.NEWDOMDOCUMENT;
  v_root := DBMS_XMLDOM.CREATEELEMENT(v_doc, 'Employees');
  v_node := DBMS_XMLDOM.APPENDCHILD(
              DBMS_XMLDOM.MAKENODE(v_doc),
              DBMS_XMLDOM.MAKENODE(v_root));

  FOR r IN c_emp LOOP
    v_emp := DBMS_XMLDOM.CREATEELEMENT(v_doc, 'Employee');
    DBMS_XMLDOM.SETATTRIBUTE(v_emp, 'id', TO_CHAR(r.employee_id));
    DBMS_XMLDOM.SETATTRIBUTE(v_emp, 'name', r.first_name || ' ' || r.last_name);
    DBMS_XMLDOM.SETATTRIBUTE(v_emp, 'salary', TO_CHAR(r.salary));
    v_node := DBMS_XMLDOM.APPENDCHILD(
                DBMS_XMLDOM.MAKENODE(v_root),
                DBMS_XMLDOM.MAKENODE(v_emp));
  END LOOP;

  SELECT XMLTYPE(DBMS_XMLDOM.GETXMLTYPE(v_doc).GETCLOBVAL())
  INTO   v_xml FROM DUAL;
  DBMS_XMLDOM.FREEDOCUMENT(v_doc);

  INSERT INTO xml_output(payload, created_at)
  VALUES (v_xml, SYSTIMESTAMP);
  COMMIT;
END;

CREATE PROCEDURE GetOrdersWithStatusAndDateRange
    @OrderID INT,
    @MinOrderDate DATE,
    @MaxOrderDate DATE
AS
BEGIN
    DECLARE @ErrorOccurred INT = 0;

    BEGIN TRY
        -- Create a temporary table to hold the filtered data
        CREATE TABLE #FilteredOrders (
            OrderID INT,
            CustomerID INT,
            OrderDate DATE,
            Status NVARCHAR(50)
        );

        -- Insert data into the temporary table based on the provided conditions
        INSERT INTO #FilteredOrders (OrderID, CustomerID, OrderDate, Status)
        SELECT OrderID, CustomerID, OrderDate, Status
        FROM Orders
        WHERE 
            OrderID = @OrderID AND 
            OrderDate BETWEEN @MinOrderDate AND @MaxOrderDate;

        -- Output the filtered data to a result set
        SELECT * FROM #FilteredOrders;
    END TRY

    BEGIN CATCH
        -- Handle any errors that occur during the execution of the stored procedure
        SET @ErrorOccurred = 1;
        DECLARE @ErrorMessage NVARCHAR(400) = ERROR_MESSAGE();
        RAISERROR('An error occurred: %s', 16, 1, @ErrorMessage);
    END CATCH

    -- Drop the temporary table if it was created
    IF @ErrorOccurred = 0 AND OBJECT_ID('#FilteredOrders') IS NOT NULL
        DROP TABLE #FilteredOrders;
END

