CREATE OR REPLACE PROCEDURE update_inventory(
    p_order_id IN NUMBER,
    p_quantity IN NUMBER
) AS
    v_current_qty NUMBER;
    v_product_name VARCHAR2(200);
BEGIN
    -- Open a cursor to fetch product details
    DECLARE
        CURSOR cur_products IS
            SELECT quantity_on_hand, product_name
            FROM products
            WHERE product_id = p_order_id
            FOR UPDATE;
    BEGIN
        -- Fetch the current inventory and product name
        OPEN cur_products;
        FETCH cur_products INTO v_current_qty, v_product_name;
        CLOSE cur_products;

        -- Check for insufficient stock
        IF v_current_qty < p_quantity THEN
            RAISE_APPLICATION_ERROR(
                -20002,
                'Insufficient stock for product: ' || v_product_name ||
                '. Available: ' || v_current_qty ||
                ', Requested: ' || p_quantity
            );
        END IF;

        -- Update the product inventory
        UPDATE products
        SET quantity_on_hand = quantity_on_hand - p_quantity,
            last_updated     = SYSDATE
        WHERE product_id = p_order_id;
    EXCEPTION
        WHEN OTHERS THEN
            DBMS_OUTPUT.PUT_LINE('An error occurred: ' || SQLERRM);
    END;
END update_inventory;

