CREATE PROCEDURE UpdateCustomerOrders
    @OrderID INT,
    @NewStatus NVARCHAR(50),
    @Note NVARCHAR(MAX)
AS
BEGIN
    SET NOCOUNT ON;

    -- Create a temporary table to hold the updated orders
    CREATE TABLE #UpdatedOrders (
        OrderID INT PRIMARY KEY,
        CustomerID INT,
        Status NVARCHAR(50),
        Note NVARCHAR(MAX)
    );

    BEGIN TRY
        -- Merge the new status and note into the Orders table
        MERGE INTO Orders AS T1
        USING #UpdatedOrders AS T2
        ON T1.OrderID = T2.OrderID
        WHEN MATCHED THEN
            UPDATE SET T1.Status = T2.Status, T1.Note = T2.Note
        WHEN NOT MATCHED BY TARGET THEN
            INSERT (OrderID, CustomerID, Status, Note) VALUES (T2.OrderID, T2.CustomerID, T2.Status, T2.Note);
    END TRY
    BEGIN CATCH
        -- Rollback the transaction in case of an error
        ROLLBACK TRANSACTION;
        DECLARE @ErrorMessage NVARCHAR(MAX);
        SELECT @ErrorMessage = ERROR_MESSAGE();
        RAISERROR('An error occurred: %s', 16, 1, @ErrorMessage);
    END CATCH

    -- Clean up the temporary table
    DROP TABLE #UpdatedOrders;

    -- Output the updated order details
    SELECT OrderID, CustomerID, Status, Note FROM Orders WHERE OrderID = @OrderID;
END

CREATE PROCEDURE GetCustomerOrders
    @CustomerId INT,
    @DaysBack INT
AS
BEGIN
    DECLARE @CutoffDate DATE;
    SET @CutoffDate = DATEADD(DAY, -@DaysBack, GETDATE());

    BEGIN TRY
        MERGE INTO CustomerOrders AS Target
        USING (
            SELECT OrderID, CustomerID, OrderDate, TotalAmount
            FROM Orders
            WHERE CustomerID = @CustomerId AND OrderDate >= @CutoffDate
        ) AS Source
        ON Target.OrderID = Source.OrderID
        WHEN MATCHED THEN
            UPDATE SET Target.TotalAmount = Source.TotalAmount
        WHEN NOT MATCHED THEN
            INSERT (OrderID, CustomerID, OrderDate, TotalAmount)
            VALUES (Source.OrderID, Source.CustomerID, Source.OrderDate, Source.TotalAmount);

        SELECT * FROM CustomerOrders;
    END TRY
    BEGIN CATCH
        DECLARE @ErrorMessage NVARCHAR(MAX);
        SET @ErrorMessage = ERROR_MESSAGE();
        RAISERROR('An error occurred: %s', 16, 1, @ErrorMessage) WITH NOWAIT;
    END CATCH;
END

CREATE OR REPLACE TRIGGER trg_update_inventory
AFTER INSERT ON order_items
FOR EACH ROW
DECLARE
    v_current_qty    NUMBER;
    v_product_name   VARCHAR2(200);
BEGIN
    SELECT quantity_on_hand, product_name
    INTO v_current_qty, v_product_name
    FROM products
    WHERE product_id = :NEW.product_id
    FOR UPDATE;

    IF v_current_qty < :NEW.quantity THEN
        RAISE_APPLICATION_ERROR(
            -20002,
            'Insufficient stock for product: ' || v_product_name ||
            '. Available: ' || v_current_qty ||
            ', Requested: ' || :NEW.quantity
        );
    END IF;

    UPDATE products
    SET quantity_on_hand = quantity_on_hand - :NEW.quantity,
        last_updated     = SYSDATE
    WHERE product_id = :NEW.product_id;

    IF (v_current_qty - :NEW.quantity) < 10 THEN
        INSERT INTO reorder_alerts (alert_id, product_id, current_qty, alert_date)
        VALUES (alert_seq.NEXTVAL, :NEW.product_id,
                v_current_qty - :NEW.quantity, SYSDATE);
    END IF;
END trg_update_inventory;

