    -- Create a temporary table to hold the new order details
    DECLARE @NewOrder AS TABLE (
        OrderID INT,
        ProductID INT,
        Quantity INT
    );

    BEGIN TRY
        -- Insert or update the order in the temporary table
        INSERT INTO @NewOrder (OrderID, ProductID, Quantity)
        VALUES (@OrderID, @ProductID, @Quantity);

        -- Perform a MERGE operation to update inventory
        MERGE INTO Orders AS T1
        USING @NewOrder AS T2
        ON T1.OrderID = T2.OrderID AND T1.ProductID = T2.ProductID
        WHEN MATCHED THEN
            UPDATE SET T1.Quantity = T1.Quantity + T2.Quantity
        WHEN NOT MATCHED THEN
            INSERT (OrderID, ProductID, Quantity) VALUES (T2.OrderID, T2.ProductID, T2.Quantity);

        -- Output the updated order details to a new table
        SELECT * FROM @NewOrder AS T3;
    END TRY
    BEGIN CATCH
        DECLARE @ErrorMessage NVARCHAR(MAX);
        SET @ErrorMessage = ERROR_MESSAGE();

        -- Rollback the transaction in case of an error
        ROLLBACK TRANSACTION;

        -- Output the error message to a new table
        INSERT INTO ErrorLog (ErrorMessage) VALUES (@ErrorMessage);
