CREATE PROCEDURE usp_UpdateCustomerOrders
    @CustomerId INT,
    @NewOrderDate DATE
AS
BEGIN
    SET NOCOUNT ON;

    -- Create a temporary table to store intermediate results
    CREATE TABLE #temp_orders (
        order_id INT,
        customer_id INT,
        product_id INT,
        quantity INT,
        order_date DATE
    );

    -- Fetch orders for the given customer from the database using a cursor
    DECLARE @order_id INT, @customer_id INT, @product_id INT, @quantity INT, @order_date DATE;
    OPEN Cursor_orders FOR
    SELECT order_id, customer_id, product_id, quantity, order_date FROM Orders WHERE customer_id = @CustomerId;

    -- Fetch data into the temporary table
    FETCH NEXT FROM Cursor_orders INTO @order_id, @customer_id, @product_id, @quantity, @order_date;
    WHILE @@FETCH_STATUS = 0
    BEGIN
        INSERT INTO #temp_orders (order_id, customer_id, product_id, quantity, order_date)
            VALUES (@order_id, @customer_id, @product_id, @quantity, @order_date);

        FETCH NEXT FROM Cursor_orders INTO @order_id, @customer_id, @product_id, @quantity, @order_date;
    END;

    CLOSE Cursor_orders;
    DEALLOCATE Cursor_orders;

    -- Perform a MERGE operation to update the orders table
    BEGIN TRY
        MERGE INTO Orders AS target
        USING #temp_orders AS source ON target.order_id = source.order_id
        WHEN MATCHED THEN
            UPDATE SET target.quantity = source.quantity, target.last_updated_at = GETDATE()
        WHEN NOT MATCHED BY TARGET THEN
            INSERT (order_id, customer_id, product_id, quantity, order_date)
            VALUES (source.order_id, source.customer_id, source.product_id, source.quantity, source.order_date);
    END TRY
    BEGIN CATCH
        -- Handle any errors that occur during the MERGE operation
        DECLARE @error_message NVARCHAR(4000) = ERROR_MESSAGE();
        RAISERROR('An error occurred while updating orders: %s', 16, 1, @error_message);
    END CATCH;

    -- Clean up the temporary table
    DROP TABLE #temp_orders;
END;

