CREATE PROCEDURE usp_MergeSalesOrders
    @OrderID INT,
    @CustomerID INT,
    @ProductID INT,
    @Quantity INT,
    @UnitPrice DECIMAL(10, 2),
    @Status NVARCHAR(50)
AS
BEGIN
    SET NOCOUNT ON;

    -- Create a temporary table to hold the new order
    DECLARE @new_order TABLE (
        OrderID INT,
        CustomerID INT,
        ProductID INT,
        Quantity INT,
        UnitPrice DECIMAL(10, 2),
        Status NVARCHAR(50)
    );

    BEGIN TRY
        -- Insert the new order into the temporary table
        INSERT INTO @new_order (OrderID, CustomerID, ProductID, Quantity, UnitPrice, Status)
        VALUES (@OrderID, @CustomerID, @ProductID, @Quantity, @UnitPrice, @Status);

        -- Merge the new order with the existing orders in the Orders table
        MERGE INTO dbo.Orders AS T1
        USING @new_order AS T2
        ON (T1.OrderID = T2.OrderID)
        WHEN MATCHED THEN
            UPDATE SET T1.Quantity = T1.Quantity + T2.Quantity,
                        T1.UnitPrice = T2.UnitPrice
        WHEN NOT MATCHED THEN
            INSERT (OrderID, CustomerID, ProductID, Quantity, UnitPrice, Status)
            VALUES (T2.OrderID, T2.CustomerID, T2.ProductID, T2.Quantity, T2.UnitPrice, T2.Status);

        -- Output the result of the MERGE operation
        SELECT * FROM dbo.Orders AS T1 INNER JOIN @new_order AS T2 ON T1.OrderID = T2.OrderID;
    END TRY
    BEGIN CATCH
        DECLARE @error_message NVARCHAR(4000);
        SET @error_message = ERROR_MESSAGE();

        -- Output the error message to the console
        PRINT 'Error: ' + @error_message;

        -- Rollback the transaction if an error occurred
        ROLLBACK TRANSACTION;
    END CATCH;
END;

