CREATE PROCEDURE GetCustomerOrders
AS
BEGIN
    -- Declare variables for output parameters
    DECLARE @CustomerID INT;
    DECLARE @CartTotal DECIMAL(18,2);
    DECLARE @DiscountAmount DECIMAL(18,2) OUTPUT;
    DECLARE @FinalTotal DECIMAL(18,2) OUTPUT;
    DECLARE @IsValid BIT OUTPUT;
    DECLARE @ValidationMessage NVARCHAR(500) OUTPUT;

    -- Set NOCOUNT ON to suppress the number of rows affected
    SET NOCOUNT ON;

    -- Try to retrieve customer orders from the Orders table
    BEGIN TRY
        -- Select customer orders and calculate discount and final total
        SELECT 
            CustomerID,
            CartTotal,
            DiscountAmount = CASE WHEN CartTotal > 100 THEN CartTotal * 0.1 ELSE 0 END, -- Example discount calculation
            FinalTotal = CartTotal - DiscountAmount,
            IsValid = 1,
            ValidationMessage = 'Order processed successfully'
        INTO #Result
        FROM Orders;
    END TRY
    BEGIN CATCH
        -- Handle errors by setting output parameters and rolling back the transaction
        SET @IsValid = 0;
        SET @ValidationMessage = ERROR_MESSAGE();
        ROLLBACK TRANSACTION;
    END CATCH

    -- Return the result set
    SELECT * FROM #Result;
END;

CREATE PROCEDURE usp_CustomerOrders (
    @CustomerID INT,
    @StartDate DATE,
    @EndDate DATE,
    @OutputTable TABLE (
        OrderID INT,
        CustomerID INT,
        ProductID INT,
        Quantity INT,
        UnitPrice DECIMAL(10, 2),
        TotalAmount DECIMAL(10, 2)
    )
AS
BEGIN
    SET NOCOUNT ON;

    BEGIN TRY
        DECLARE @CustomerOrdersTemp TABLE (
            OrderID INT,
            CustomerID INT,
            ProductID INT,
            Quantity INT,
            UnitPrice DECIMAL(10, 2),
            TotalAmount DECIMAL(10, 2)
        );

        INSERT INTO @CustomerOrdersTemp
        SELECT o.OrderID, o.CustomerID, i.ProductID, o.Quantity, i.UnitPrice, o.Quantity * i.UnitPrice AS TotalAmount
        FROM Orders o
        INNER JOIN OrderDetails od ON o.OrderID = od.OrderID
        INNER JOIN Products i ON od.ProductID = i.ProductID
        WHERE o.OrderDate BETWEEN @StartDate AND @EndDate;

        MERGE INTO dbo.CustomerOrders AS T1
        USING @CustomerOrdersTemp AS T2
        ON T1.OrderID = T2.OrderID
        WHEN NOT MATCHED THEN
            INSERT (OrderID, CustomerID, ProductID, Quantity, UnitPrice, TotalAmount)
            VALUES (T2.OrderID, T2.CustomerID, T2.ProductID, T2.Quantity, T2.UnitPrice, T2.TotalAmount);

        COMMIT TRANSACTION;
    END TRY
    BEGIN CATCH
        ROLLBACK TRANSACTION;
        THROW;
    END CATCH;

    SELECT * FROM @CustomerOrdersTemp AS T1;
END;

CREATE OR REPLACE PROCEDURE validate_and_apply_salary_updates(
    p_employee_id IN NUMBER,
    p_new_salary IN NUMBER
) IS
    v_old_salary NUMBER;
    v_pct_change NUMBER;
BEGIN
    -- Fetch old salary using CURSOR
    DECLARE
        CURSOR c_employee_salary IS
            SELECT salary FROM employees WHERE employee_id = p_employee_id;
        v_employee_salary NUMBER;
    BEGIN
        OPEN c_employee_salary;
        FETCH c_employee_salary INTO v_employee_salary;
        CLOSE c_employee_salary;
    EXCEPTION
        WHEN NO_DATA_FOUND THEN
            RAISE_APPLICATION_ERROR(-20001, 'Employee not found');
    END;

    -- Calculate percentage change
    v_pct_change := ROUND((v_old_salary - p_new_salary) / v_old_salary * 100, 2);

    -- Validate: find violations
    IF v_pct_change > 20 THEN
        RAISE_APPLICATION_ERROR(
            -20001,
            'Salary decrease of ' || v_pct_change ||
            '% exceeds the maximum allowed 20% reduction for employee ' ||
            p_employee_id
        );
    END IF;

    -- Log valid salary decreases
    INSERT INTO salary_change_log (
        log_id, employee_id, old_salary, new_salary, pct_change,
        change_type, logged_at
    ) VALUES (
        (SELECT log_seq.NEXTVAL FROM dual),
        p_employee_id,
        v_old_salary,
        p_new_salary,
        -v_pct_change,
        'DECREASE',
        SYSDATE
    );

    -- Apply valid updates using stored procedure
    BEGIN
        UPDATE employees SET salary = p_new_salary WHERE employee_id = p_employee_id;
    EXCEPTION
        WHEN OTHERS THEN
            DBMS_OUTPUT.PUT_LINE('Error updating salary: ' || SQLERRM);
    END;

    DBMS_OUTPUT.PUT_LINE('Salary update applied successfully');
END validate_and_apply_salary_updates;
/

