CREATE PROCEDURE UpdateCustomerAddresses
    @CustomerID INT,
    @NewAddress NVARCHAR(100),
    @UpdateFlag BIT OUTPUT
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @CurrentAddress NVARCHAR(100);
    DECLARE @IsMatch BIT;
    DECLARE @Cursor CURSOR FOR
        SELECT Address FROM Customers WHERE CustomerID = @CustomerID;

    OPEN @Cursor;

    FETCH NEXT FROM @Cursor INTO @CurrentAddress;

    WHILE @@FETCH_STATUS = 0
    BEGIN
        SET @IsMatch = CASE 
            WHEN @NewAddress = @CurrentAddress THEN 1
            ELSE 0
        END;

        IF @IsMatch = 0
        BEGIN
            UPDATE Customers
            SET Address = @NewAddress
            WHERE CustomerID = @CustomerID;
        END

        FETCH NEXT FROM @Cursor INTO @CurrentAddress;
    END

    CLOSE @Cursor;
    DEALLOCATE @Cursor;

    SET @UpdateFlag = @@FETCH_STATUS = 0;
END

DECLARE
  v_portfolio_id  NUMBER := 2045;
  v_total_nav     NUMBER := 0;
  v_asset_count   NUMBER := 0;
  CURSOR c_assets IS
    SELECT asset_id, asset_type, market_value, weight
    FROM portfolio_holdings
    WHERE portfolio_id = v_portfolio_id
    AND active_flag = 'Y';
BEGIN
  FOR rec IN c_assets LOOP
    v_total_nav   := v_total_nav + rec.market_value;
    v_asset_count := v_asset_count + 1;
    UPDATE portfolio_holdings
    SET last_valued_at = SYSDATE
    WHERE asset_id = rec.asset_id
    AND portfolio_id = v_portfolio_id;
  END LOOP;
  UPDATE portfolio_summary
  SET total_nav = v_total_nav,
      asset_count = v_asset_count,
      last_refreshed = SYSDATE
  WHERE portfolio_id = v_portfolio_id;
  COMMIT;
EXCEPTION
  WHEN NO_DATA_FOUND THEN
    DBMS_OUTPUT.PUT_LINE('No active holdings for portfolio: ' || v_portfolio_id);
  WHEN OTHERS THEN
    ROLLBACK;
    RAISE;
END;

DECLARE
    TYPE employee_cursor IS REF CURSOR;
    v_employee_record employees%ROWTYPE;
BEGIN
    -- Open the cursor
    OPEN employee_cursor;

    -- Fetch multiple records into an array
    DECLARE
        v_employee_records employees%ROWTYPE[];
    BEGIN
        FETCH employee_cursor BULK COLLECT INTO v_employee_records LIMIT 100;
    END;

    -- Process each record
    FOR i IN 1..v_employee_records.COUNT LOOP
        DBMS_OUTPUT.PUT_LINE('Employee ID: ' || v_employee_records(i).employee_id);
        DBMS_OUTPUT.PUT_LINE('First Name: ' || v_employee_records(i).first_name);
        DBMS_OUTPUT.PUT_LINE('Last Name: ' || v_employee_records(i).last_name);
    END LOOP;

    -- Close the cursor
    CLOSE employee_cursor;
EXCEPTION
    WHEN OTHERS THEN
        DBMS_OUTPUT.PUT_LINE('An error occurred: ' || SQLERRM);
END;
/

CREATE PROCEDURE ProcessCustomerOrders
    @OrderID INT,
    @ProcessedQty INT OUTPUT,
    @BackorderedQty INT OUTPUT,
    @TotalValue DECIMAL(18,2) OUTPUT,
    @ProcessingStatus NVARCHAR(50) OUTPUT
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @RequestedQty INT;
    DECLARE @AvailableQty INT;
    DECLARE @UnitPrice DECIMAL(10,2);
    DECLARE @ProductID INT;

    SELECT
        @ProductID = oi.ProductID,
        @RequestedQty = oi.Quantity,
        @UnitPrice = oi.UnitPrice
    FROM OrderItems oi
    WHERE oi.OrderID = @OrderID;

    BEGIN TRY
        SELECT @AvailableQty = QuantityOnHand
        FROM Inventory
        WHERE ProductID = @ProductID;
    END TRY
    BEGIN CATCH
        SET @ProcessedQty = 0;
        SET @BackorderedQty = @RequestedQty;
        SET @TotalValue = 0;
        SET @ProcessingStatus = 'PRODUCT_NOT_FOUND';
        RETURN;
    END CATCH

    IF @AvailableQty IS NULL
    BEGIN
        SET @ProcessedQty = 0;
        SET @BackorderedQty = @RequestedQty;
        SET @TotalValue = 0;
        SET @ProcessingStatus = 'PRODUCT_NOT_FOUND';
        RETURN;
    END

    IF @AvailableQty >= @RequestedQty
    BEGIN
        SET @ProcessedQty = @RequestedQty;
        SET @BackorderedQty = 0;
        SET @TotalValue = @RequestedQty * @UnitPrice;
        SET @ProcessingStatus = 'FULLY_PROCESSED';

        UPDATE Inventory
        SET QuantityOnHand = QuantityOnHand - @RequestedQty
        WHERE ProductID = @ProductID;
    END
    ELSE IF @AvailableQty > 0
    BEGIN
        SET @ProcessedQty = @AvailableQty;
        SET @BackorderedQty = @RequestedQty - @AvailableQty;
        SET @TotalValue = @AvailableQty * @UnitPrice;
        SET @ProcessingStatus = 'PARTIALLY_PROCESSED';

        UPDATE Inventory
        SET QuantityOnHand = 0
        WHERE ProductID = @ProductID;
    END
    ELSE
    BEGIN
        SET @ProcessedQty = 0;
        SET @BackorderedQty = @RequestedQty;
        SET @TotalValue = 0;
        SET @ProcessingStatus = 'OUT_OF_STOCK';
    END
END

DECLARE
  TYPE emp_cursor IS REF CURSOR;
  v_emp_rec employees%ROWTYPE;
  v_total_salary NUMBER := 0;
  v_emp_count NUMBER := 0;

  PROCEDURE fetch_employees(p_department_id IN NUMBER) AS
    BEGIN
      OPEN emp_cursor FOR SELECT * FROM employees WHERE department_id = p_department_id;
      LOOP
        FETCH emp_cursor INTO v_emp_rec;
        EXIT WHEN emp_cursor%NOTFOUND;
        v_total_salary := v_total_salary + v_emp_rec.salary;
        v_emp_count := v_emp_count + 1;
      END LOOP;
      CLOSE emp_cursor;
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        DBMS_OUTPUT.PUT_LINE('No data found.');
      WHEN OTHERS THEN
        DBMS_OUTPUT.PUT_LINE('Error: ' || SQLERRM);
    END fetch_employees;

BEGIN
  fetch_employees(30);

  IF v_emp_count = 0 THEN
    RAISE_APPLICATION_ERROR(-20001, 'No employees found in department 30');
  END IF;

  DBMS_OUTPUT.PUT_LINE('Avg Salary: ' || TO_CHAR(v_total_salary / v_emp_count));
EXCEPTION
  WHEN NO_DATA_FOUND THEN
    DBMS_OUTPUT.PUT_LINE('No data found.');
  WHEN OTHERS THEN
    DBMS_OUTPUT.PUT_LINE('Error: ' || SQLERRM);
END;

DECLARE
  TYPE emp_id_list IS TABLE OF employees.emp_id%TYPE;
  v_ids   emp_id_list;
  v_limit PLS_INTEGER := 100;
  CURSOR c IS SELECT emp_id FROM employees WHERE status = 'INACTIVE';
BEGIN
  OPEN c;
  LOOP
    FETCH c BULK COLLECT INTO v_ids LIMIT v_limit;
    EXIT WHEN v_ids.COUNT = 0;
    FORALL i IN 1 .. v_ids.COUNT
      DELETE FROM employees WHERE emp_id = v_ids(i);
    COMMIT;
  END LOOP;
  CLOSE c;

  -- Example of a stored procedure to handle exceptions and log output
  CREATE OR REPLACE PROCEDURE delete_inactive_employees AS
    BEGIN
      DECLARE
        v_emp_id emp_id%TYPE;
        v_error_msg VARCHAR2(100);
      BEGIN
        OPEN c;
        LOOP
          FETCH c BULK COLLECT INTO v_ids LIMIT v_limit;
          EXIT WHEN v_ids.COUNT = 0;
          FORALL i IN 1 .. v_ids.COUNT
            DELETE FROM employees WHERE emp_id = v_ids(i);
          COMMIT;
        END LOOP;
        CLOSE c;

        -- Example of logging output using DBMS_OUTPUT
        DBMS_OUTPUT.PUT_LINE('Deleted ' || v_ids.COUNT || ' inactive employees.');
      EXCEPTION
        WHEN OTHERS THEN
          v_error_msg := SQLERRM;
          DBMS_OUTPUT.PUT_LINE('Error deleting inactive employees: ' || v_error_msg);
      END;
    END delete_inactive_employees;
END;

