WITH filtered_orders AS (
    SELECT o.order_id, c.customer_id, o.order_date, p.name, p.price
    FROM customers c
    JOIN orders o ON c.customer_id = o.customer_id
    JOIN products p ON o.product_id = p.product_id
    WHERE o.order_date BETWEEN '2023-01-01' AND '2023-01-15'
)

