FROM customers c
CROSS JOIN filtered_orders o;

CREATE PROCEDURE GetCustomerOrders
    @CustomerID INT,
    @DaysBack INT
AS
BEGIN
    DECLARE @OrderID INT;
    DECLARE @TotalAmount DECIMAL(10, 2);

    BEGIN TRY
        -- Try to find the last order for the customer within the specified date range
        SELECT TOP 1 @OrderID = OrderID, @TotalAmount = TotalAmount
        FROM Orders
        WHERE CustomerID = @CustomerID AND OrderDate >= DATEADD(DAY, -@DaysBack, GETDATE())
    END TRY

    BEGIN CATCH
        -- Handle any errors that occur during the try block
        DECLARE @ErrorMsg NVARCHAR(MAX);
        SELECT @ErrorMsg = ERROR_MESSAGE();

        RAISERROR('An error occurred while processing the request: %s', 16, 1, @ErrorMsg);

        -- Output the error message to the client
        SELECT 'Error: ' + @ErrorMsg AS ErrorMessage;
    END CATCH

    -- Return the last order details if found
    RETURN @OrderID, @TotalAmount;
END

