CREATE PROCEDURE GetCustomerOrders
AS
BEGIN
    DECLARE @OrderID INT;
    DECLARE @CustomerID INT;

    -- Create a temporary table to store customer orders
    CREATE TABLE #CustomerOrders (
        OrderID INT,
        CustomerID INT,
        OrderDate DATE
    );

    -- Insert data into the temporary table using a MERGE statement
    MERGE INTO #CustomerOrders AS T1
    USING Orders AS T2
    ON T1.CustomerID = T2.CustomerID AND T1.OrderDate = T2.OrderDate
    WHEN NOT MATCHED THEN
        INSERT (OrderID, CustomerID, OrderDate)
        VALUES (T2.OrderID, T2.CustomerID, T2.OrderDate);

    -- Try/Catch block to handle errors during the MERGE operation
    BEGIN TRY
        -- Perform some operations that might fail
        SELECT * FROM #CustomerOrders;
    END TRY
    BEGIN CATCH
        DECLARE @ErrorMessage NVARCHAR(4000);
        SET @ErrorMessage = ERROR_MESSAGE();
        RAISERROR(@ErrorMessage, 16, 1);
    END CATCH;

    -- Output the results from the temporary table
    SELECT * FROM #CustomerOrders;
END

CREATE PROCEDURE UpdateCustomerAddress
    @CustomerID INT,
    @NewAddress VARCHAR(100),
    @NewCity VARCHAR(50),
    @NewState VARCHAR(2),
    @NewZipCode VARCHAR(10)
AS
BEGIN
    SET NOCOUNT ON;

    -- Create a temporary table to hold the new address data
    CREATE TABLE #TempAddresses (
        CustomerID INT,
        NewAddress VARCHAR(100),
        NewCity VARCHAR(50),
        NewState VARCHAR(2),
        NewZipCode VARCHAR(10)
    );

    -- Insert the new address data into the temporary table
    INSERT INTO #TempAddresses (CustomerID, NewAddress, NewCity, NewState, NewZipCode)
    VALUES (@CustomerID, @NewAddress, @NewCity, @NewState, @NewZipCode);

    -- Use a TRY/CATCH block to handle potential errors during the merge operation
    BEGIN TRY
        -- Merge the new address data into the Customers table using a MERGE statement
        MERGE INTO Customers AS T1
        USING #TempAddresses AS T2 ON T1.CustomerID = T2.CustomerID
        WHEN MATCHED THEN
            UPDATE SET T1.Address = T2.NewAddress, T1.City = T2.NewCity, T1.State = T2.NewState, T1.ZipCode = T2.NewZipCode
        WHEN NOT MATCHED THEN
            INSERT (CustomerID, Address, City, State, ZipCode) VALUES (T2.CustomerID, T2.NewAddress, T2.NewCity, T2.NewState, T2.NewZipCode);
    END TRY
    BEGIN CATCH
        -- Handle any errors that occur during the merge operation
        DECLARE @ErrorMessage NVARCHAR(MAX) = ERROR_MESSAGE();
        RAISERROR('Error updating customer address: %s', 16, 1, @ErrorMessage);
    END CATCH;

    -- Clean up the temporary table
    DROP TABLE #TempAddresses;
END

-- Example call to the stored procedure
EXEC UpdateCustomerAddress @CustomerID = 123, @NewAddress = '456 Elm St', @NewCity = 'Anytown', @NewState = 'CA', @NewZipCode = '12345';

CREATE PROCEDURE EvaluateOrderProcessing
    @OrderId INT,
    @CustomerID INT,
    @ProductID INT,
    @Quantity INT,
    @TotalAmount DECIMAL(18,2),
    @Status NVARCHAR(50) OUTPUT
AS
BEGIN
    SET NOCOUNT ON;

    -- Create a temporary table to store intermediate results
    CREATE TABLE #OrderDetails (
        OrderId INT,
        CustomerID INT,
        ProductID INT,
        Quantity INT,
        TotalAmount DECIMAL(18,2)
    );

    -- Insert the incoming order details into the temporary table
    INSERT INTO #OrderDetails (OrderId, CustomerID, ProductID, Quantity, TotalAmount)
    VALUES (@OrderId, @CustomerID, @ProductID, @Quantity, @TotalAmount);

    -- Use a TRY/CATCH block to handle potential errors during processing
    BEGIN TRY
        -- Perform the MERGE operation on the Orders table
        MERGE INTO Orders AS T1
        USING #OrderDetails AS T2
        ON T1.OrderId = T2.OrderId
        WHEN MATCHED THEN
            UPDATE SET T1.Quantity = T1.Quantity + T2.Quantity, T1.TotalAmount = T1.TotalAmount + T2.TotalAmount
        WHEN NOT MATCHED THEN
            INSERT (OrderId, CustomerID, ProductID, Quantity, TotalAmount)
            VALUES (T2.OrderId, T2.CustomerID, T2.ProductID, T2.Quantity, T2.TotalAmount);

        -- Set the status of the order in the Orders table
        UPDATE Orders SET Status = 'PROCESSING' WHERE OrderId = @OrderId;

        -- Update the total amount in the Orders table
        UPDATE Orders SET TotalAmount = TotalAmount + (Quantity * TotalAmount) / 100 WHERE OrderId = @OrderId;

        -- Set the status of the order to 'SHIPPED' after processing
        UPDATE Orders SET Status = 'SHIPPED' WHERE OrderId = @OrderId;
    END TRY
    BEGIN CATCH
        -- Handle errors that occur during the MERGE operation
        DECLARE @ErrorMessage NVARCHAR(4000);
        SELECT @ErrorMessage = ERROR_MESSAGE();
        SET @Status = 'ERROR';
        RAISERROR(@ErrorMessage, 16, 1);

        -- Rollback any changes made to the Orders table if an error occurs
        ROLLBACK TRANSACTION;
    END CATCH;

    -- Set the status of the order in the Orders table after processing
    UPDATE Orders SET Status = 'SHIPPED' WHERE OrderId = @OrderId;

    -- Return the status of the order
    SELECT @Status AS Status;
END

DECLARE
  CURSOR emp_cursor IS SELECT * FROM employees;
  v_emp_id NUMBER;
  v_salary NUMBER;
  v_job_id VARCHAR2(20);
  v_bonus NUMBER := 0;
BEGIN
  OPEN emp_cursor;

  LOOP
    FETCH emp_cursor INTO v_emp_id, v_salary, v_job_id;
    EXIT WHEN emp_cursor%NOTFOUND;

    IF v_job_id LIKE 'SA%' THEN
      v_bonus := v_salary * 0.20;
    ELSIF v_job_id LIKE 'IT%' THEN
      v_bonus := v_salary * 0.15;
    ELSE
      v_bonus := v_salary * 0.10;
    END IF;

    DBMS_OUTPUT.PUT_LINE('Employee ID: ' || v_emp_id || ', Bonus: ' || v_bonus);
  END LOOP;

  CLOSE emp_cursor;
EXCEPTION
  WHEN NO_DATA_FOUND THEN
    DBMS_OUTPUT.PUT_LINE('No employees found.');
END;

