from pyspark.sql.functions import col, when
from pyspark.sql import SparkSession

def calc_bonus_col(salary_col, job_id_col):
    return (
        when(job_id_col.like('SA%'), salary_col * 0.20)
        .when(job_id_col.like('IT%'), salary_col * 0.15)
        .otherwise(salary_col * 0.10)
    )

def apply_bonuses(dept_id):
    df = spark.table('employees')
    updated_df = df.withColumn(
        'bonus',
        when(
            col('department_id') == dept_id,
            calc_bonus_col(col('salary'), col('job_id'))
        ).otherwise(col('bonus'))
    )
    updated_df.write.mode('overwrite').saveAsTable('employees')

apply_bonuses(p_dept_id=80)

