CREATE OR REPLACE PROCEDURE get_employee_totals (
  p_department IN VARCHAR2,
  p_output OUT SYS_REFCURSOR
) AS
BEGIN
  OPEN p_output FOR
    SELECT employee_id, first_name, last_name, department_id, salary
    FROM employees
    WHERE department_id = p_department;
END get_employee_totals;

CREATE OR REPLACE FUNCTION get_total_salaries (
  p_department IN VARCHAR2
) RETURN NUMBER IS
  v_total_salary NUMBER := 0;
BEGIN
  FOR rec IN (SELECT salary FROM employees WHERE department_id = p_department) LOOP
    v_total_salary := v_total_salary + rec.salary;
  END LOOP;

  RETURN v_total_salary;
END get_total_salaries;

CREATE OR REPLACE PROCEDURE update_salaries (
    p_department_id IN NUMBER,
    p_increment_rate IN NUMBER
) IS
  v_employee_cursor SYS_REFCURSOR;
  v_employee_record employees%ROWTYPE;
BEGIN
  -- Open the cursor to fetch employees from the specified department
  OPEN v_employee_cursor FOR
    SELECT * FROM employees WHERE department_id = p_department_id;

  -- Fetch all employees in a single operation
  BULK COLLECT INTO v_employee_record FROM v_employee_cursor;

  -- Close the cursor
  CLOSE v_employee_cursor;

  -- Process each employee record
  FOR i IN 1..v_employee_record.COUNT LOOP
    UPDATE employees SET salary = salary * (1 + p_increment_rate) WHERE id = v_employee_record(i).id;
  END LOOP;

EXCEPTION
  WHEN OTHERS THEN
    -- Log the error and rollback the transaction
    DBMS_OUTPUT.PUT_LINE('Error: ' || SQLERRM);
    ROLLBACK;
END update_salaries;
/

CREATE OR REPLACE PROCEDURE get_department_stats AS
  TYPE dept_salary_rec IS RECORD (
    department_id   NUMBER,
    total_salary    NUMBER,
    avg_salary      NUMBER,
    headcount       NUMBER
  );
  TYPE dept_salary_tab IS TABLE OF dept_salary_rec INDEX BY PLS_INTEGER;
  v_dept_stats dept_salary_tab;
  i PLS_INTEGER := 1;
BEGIN
  BEGIN
    FOR rec IN (
      SELECT department_id,
             SUM(salary) AS total_salary,
             AVG(salary) AS avg_salary,
             COUNT(*) AS headcount
      FROM employees
      GROUP BY department_id
    ) LOOP
      v_dept_stats(i).department_id := rec.department_id;
      v_dept_stats(i).total_salary  := rec.total_salary;
      v_dept_stats(i).avg_salary    := rec.avg_salary;
      v_dept_stats(i).headcount     := rec.headcount;
      i := i + 1;
    END LOOP;

    FOR j IN 1 .. v_dept_stats.COUNT LOOP
      DBMS_OUTPUT.PUT_LINE('Dept: ' || v_dept_stats(j).department_id
        || ' Avg: ' || ROUND(v_dept_stats(j).avg_salary, 2));
    END LOOP;
  EXCEPTION
    WHEN OTHERS THEN
      DBMS_OUTPUT.PUT_LINE('An error occurred: ' || SQLERRM);
  END;
END get_department_stats;
/

CREATE PROCEDURE usp_IncrementalETL
    @SourceTable  NVARCHAR(128),
    @TargetTable  NVARCHAR(128),
    @WatermarkCol NVARCHAR(128)
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @LastWatermark DATETIME2;
    DECLARE @NewWatermark  DATETIME2 = SYSUTCDATETIME();
    DECLARE @sql           NVARCHAR(MAX);

    SELECT @LastWatermark = last_loaded_at
    FROM   etl_watermarks
    WHERE  source_table = @SourceTable;

    IF @LastWatermark IS NULL SET @LastWatermark = '1900-01-01';

    SET @sql = N'INSERT INTO ' + QUOTENAME(@TargetTable) + N'
        SELECT * FROM ' + QUOTENAME(@SourceTable) + N'
        WHERE ' + QUOTENAME(@WatermarkCol) + N' > @lwm
          AND ' + QUOTENAME(@WatermarkCol) + N' <= @nwm';

    EXEC sp_executesql @sql,
         N'@lwm DATETIME2, @nwm DATETIME2',
         @lwm = @LastWatermark, @nwm = @NewWatermark;

    MERGE etl_watermarks AS tgt
    USING (SELECT @SourceTable AS source_table, @NewWatermark AS last_loaded_at) AS src
        ON tgt.source_table = src.source_table
    WHEN MATCHED THEN
        UPDATE SET tgt.last_loaded_at = src.last_loaded_at
    WHEN NOT MATCHED THEN
        INSERT (source_table, last_loaded_at)
        VALUES (src.source_table, src.last_loaded_at);
END;

DECLARE
  CURSOR c_segments IS
    SELECT segment_id, segment_name, min_spend, max_spend
    FROM loyalty_segments
    ORDER BY min_spend;
  v_updated NUMBER := 0;
BEGIN
  FOR seg IN c_segments LOOP
    UPDATE loyalty_members
    SET segment_id = seg.segment_id,
        segment_updated_at = SYSDATE
    WHERE annual_spend BETWEEN seg.min_spend AND seg.max_spend
    AND (segment_id <> seg.segment_id OR segment_id IS NULL);
    v_updated := v_updated + SQL%ROWCOUNT;
  END LOOP;
  UPDATE loyalty_members
  SET segment_id = NULL,
      segment_updated_at = SYSDATE
  WHERE annual_spend IS NULL;
  DBMS_OUTPUT.PUT_LINE('Total members re-segmented: ' || v_updated);
  COMMIT;
END;

CREATE PROCEDURE UpdateProductPrices
    @ProductId INT,
    @NewPrice DECIMAL(18,2),
    @IsUpdate BIT = 0 OUTPUT
AS
BEGIN
    SET NOCOUNT ON;

    -- Create a temporary table to hold the new price
    CREATE TABLE #TempPrices (
        ProductId INT,
        NewPrice DECIMAL(18,2)
    );

    -- Insert the new price into the temporary table
    INSERT INTO #TempPrices (ProductId, NewPrice) VALUES (@ProductId, @NewPrice);

    BEGIN TRY
        -- Merge the new price into the main Products table using a MERGE statement
        MERGE INTO Products AS T1
        USING #TempPrices AS T2 ON T1.ProductId = T2.ProductId
        WHEN MATCHED THEN
            UPDATE SET T1.Price = T2.NewPrice
        WHEN NOT MATCHED THEN
            INSERT (ProductId, Price) VALUES (T2.ProductId, T2.NewPrice);

        -- Set the output parameter based on the success of the MERGE operation
        IF @@ROWCOUNT > 0
            SET @IsUpdate = 1;
        ELSE
            SET @IsUpdate = 0;
    END TRY
    BEGIN CATCH
        -- Handle any errors that occur during the MERGE statement
        DECLARE @ErrorMessage NVARCHAR(MAX);
        SELECT @ErrorMessage = ERROR_MESSAGE();
        RAISERROR('An error occurred while updating product prices: %s', 16, 1, @ErrorMessage) WITH NOWAIT;
        SET @IsUpdate = 0;
    END CATCH;

    -- Drop the temporary table
    DROP TABLE #TempPrices;
END

DECLARE
  CURSOR employee_cursor IS
    SELECT first_name, last_name
    FROM employees
    WHERE salary > 5000;

  TYPE employee_record_type IS RECORD (
    first_name VARCHAR2(100),
    last_name VARCHAR2(100)
  );

  TYPE employee_table_type IS TABLE OF employee_record_type;
  v_employee_table employee_table_type := employee_table_type();

BEGIN
