CREATE PROCEDURE usp_MergeCustomerOrders
    @OrderId INT,
    @NewOrderStatus NVARCHAR(50),
    @NewOrderDate DATE = NULL
AS
BEGIN
    SET NOCOUNT ON;
    SET @NewOrderDate = ISNULL(@NewOrderDate, GETDATE());

    DECLARE @temp_table TABLE (
        OrderId INT,
        NewOrderStatus NVARCHAR(50),
        NewOrderDate DATE
    );

    BEGIN TRANSACTION;

    BEGIN TRY
        -- Step 1: Insert new order into temp table
        INSERT INTO #temp_table (OrderId, NewOrderStatus, NewOrderDate)
        SELECT @OrderId, @NewOrderStatus, @NewOrderDate;

        -- Step 2: Merge the new order with existing orders in Orders table
        MERGE INTO Orders AS T1
        USING #temp_table AS T2 ON T1.OrderId = T2.OrderId
        WHEN MATCHED THEN
            UPDATE SET 
                OrderStatus = T2.NewOrderStatus,
                OrderDate = T2.NewOrderDate
        WHEN NOT MATCHED THEN
            INSERT (
                OrderId, NewOrderStatus, OrderDate
            )
            VALUES (
                T2.OrderId, T2.NewOrderStatus, T2.NewOrderDate
            );

        COMMIT TRANSACTION;
    END TRY
    BEGIN CATCH
        ROLLBACK TRANSACTION;

        -- Log the error to ErrorLog table
        INSERT INTO ErrorLog (ProcedureName, ErrorMessage, ErrorTime)
        VALUES ('usp_MergeCustomerOrders', ERROR_MESSAGE(), GETDATE());

        THROW;
    END CATCH

    -- Return the updated Orders table for confirmation
    SELECT * FROM Orders WHERE OrderId = @OrderId;
END

