CREATE OR REPLACE PROCEDURE calculate_interest (
    p_principal IN NUMBER,
    p_annual_rate IN NUMBER,
    p_years IN NUMBER
) IS
    v_cursor SYS_REFCURSOR;
    v_row employees%ROWTYPE;
    v_total_periods NUMBER := 0;
    v_final_amount NUMBER := 0;
BEGIN
    -- Open a cursor to fetch employee records
    OPEN v_cursor FOR SELECT * FROM employees;

    -- Fetch all rows from the cursor into a collection
    LOOP
        FETCH v_cursor INTO v_row;
        EXIT WHEN v_cursor%NOTFOUND;

        -- Calculate the number of periods based on annual rate and years
        v_total_periods := v_total_periods + p_years;

        -- Compute the final amount using the formula A = P * (1 + r/n)^(n*t)
        v_final_amount := v_principal * POWER(1 + (p_annual_rate / 100) / 12, v_total_periods);

        -- Output the results
        DBMS_OUTPUT.PUT_LINE('Employee ID: ' || v_row.employee_id || ', Salary: ' || v_row.salary);
    END LOOP;

    -- Close the cursor
    CLOSE v_cursor;
EXCEPTION
    WHEN OTHERS THEN
        DBMS_OUTPUT.PUT_LINE('Error in calculating interest: ' || SQLERRM);
END calculate_interest;

