    try:
        result = spark.table('dbo.Orders').where(col('OrderId') == order_id).update(
            {
                'CustomerEmail': new_email,
                'CustomerPhone': new_phone
            }
        )

        if result.rowcount > 0:
            print(f'Order {order_id} updated successfully.')
        else:
            print(f'Order {order_id} does not exist.')

    except Exception as e:
        # Log the error and return an error message to the caller.
        print(f'Error updating customer order: {e}')
        raise

    # If the update fails, create a new record in the Orders table.
    if result.rowcount == 0:
        spark.table('dbo.Orders').insertInto(
            'dbo.Orders',
            values=[
                (order_id, new_email, new_phone)
            ],
            overwrite=True
        )

    return True

