CREATE PROCEDURE GetTopSalesByProduct
    @MinQuantity INT,
    @MaxQuantity INT,
    @MinPrice DECIMAL(18,2),
    @MaxPrice DECIMAL(18,2)
AS
BEGIN
    DECLARE @ErrorOccurred BIT = 0;

    BEGIN TRY
        -- Create a temporary table to store the top sales
        CREATE TABLE #TopSales (
            ProductID INT,
            Quantity INT,
            Price DECIMAL(18,2),
            TotalRevenue DECIMAL(18,2)
        );

        -- Populate the temporary table with data
        INSERT INTO #TopSales (ProductID, Quantity, Price, TotalRevenue)
        SELECT 
            O.ProductID,
            O.Quantity,
            P.Price,
            O.Quantity * P.Price AS TotalRevenue
        FROM Orders O
        JOIN Products P ON O.ProductID = P.ProductID
        WHERE O.Quantity BETWEEN @MinQuantity AND @MaxQuantity
          AND P.Price BETWEEN @MinPrice AND @MaxPrice
        ORDER BY TotalRevenue DESC;

        -- Select the top sales
        SELECT TOP 10 * 
        FROM #TopSales;

        -- Clean up the temporary table
        DROP TABLE #TopSales;
    END TRY

    BEGIN CATCH
        SET @ErrorOccurred = 1;
        DECLARE @ErrorMessage NVARCHAR(MAX);
        SELECT @ErrorMessage = ERROR_MESSAGE();
        RAISERROR('An error occurred: %s', 16, 1, @ErrorMessage);
    END CATCH;

    -- Return the result based on whether an error occurred or not
    IF @ErrorOccurred = 0
    BEGIN
        RETURN 0;
    END
    ELSE
    BEGIN
        RETURN -1;
    END;
END;

