CREATE PROCEDURE usp_MergeOrdersWithCustomers
    @OrderID INT,
    @CustomerName NVARCHAR(100),
    @Status NVARCHAR(50)
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @sql NVARCHAR(MAX);

    -- Create a temporary table to store the new order
    CREATE TABLE #NewOrders (
        OrderID INT PRIMARY KEY,
        CustomerName NVARCHAR(100),
        Status NVARCHAR(50)
    );

    -- Insert the new order into the temporary table
    INSERT INTO #NewOrders (OrderID, CustomerName, Status)
    VALUES (@OrderID, @CustomerName, @Status);

    -- Start a try block to handle any errors during the merge operation
    BEGIN TRY
        -- Perform the MERGE statement to update or insert orders
        MERGE INTO Orders AS T1
        USING #NewOrders AS T2 ON T1.OrderID = T2.OrderID
        WHEN MATCHED THEN
            UPDATE SET T1.CustomerName = T2.CustomerName, T1.Status = T2.Status
        WHEN NOT MATCHED BY TARGET THEN
            INSERT (OrderID, CustomerName, Status) VALUES (T2.OrderID, T2.CustomerName, T2.Status);

        -- Commit the transaction if the MERGE operation was successful
        COMMIT TRANSACTION;
    END TRY
    BEGIN CATCH
        -- Rollback the transaction if an error occurred
        ROLLBACK TRANSACTION;

        -- Output the error details to the log table
        INSERT INTO LogTable (ErrorDetails) VALUES (ERROR_MESSAGE());

        -- Raise an exception with a custom message
        THROW 50001, 'An error occurred while merging orders.', 1;
    END CATCH;
END;

