CREATE PROCEDURE GetCustomerOrders
    @CustomerID INT,
    @TopN INT
AS
BEGIN
    DECLARE @Cursor CURSOR FOR SELECT OrderID FROM Orders WHERE CustomerID = @CustomerID;

    OPEN @Cursor;

    FETCH NEXT FROM @Cursor INTO @OrderID;

    WHILE @@FETCH_STATUS = 0
    BEGIN
        INSERT INTO #TempOrders (OrderID)
        VALUES (@OrderID);

        FETCH NEXT FROM @Cursor INTO @OrderID;
    END

    CLOSE @Cursor;
    DEALLOCATE @Cursor;

    MERGE Orders AS T1
    USING #TempOrders AS T2
    ON T1.OrderID = T2.OrderID
    WHEN NOT MATCHED BY TARGET THEN
        INSERT (CustomerID, OrderID) VALUES (@CustomerID, T2.OrderID)
    WHEN MATCHED THEN
        UPDATE SET T1.Status = 'Processed';

    SELECT TOP (@TopN) CustomerID, OrderID, Status
    FROM Orders
    ORDER BY Status ASC;
END

CREATE PROCEDURE GetOrdersByCustomerID
    @CustomerID INT,
    @MinOrderAmount DECIMAL(18,2),
    @MaxOrderAmount DECIMAL(18,2)
AS
BEGIN
    BEGIN TRY
        -- Check if the customer exists
        IF NOT EXISTS (SELECT 1 FROM Customers WHERE CustomerID = @CustomerID)
        BEGIN
            RAISERROR('Invalid Customer ID', 16, 1);
            RETURN;
        END

        -- Create a temporary table to store filtered orders
        CREATE TABLE #FilteredOrders (
            OrderID INT,
            CustomerID INT,
            ProductID INT,
            Quantity INT,
            TotalAmount DECIMAL(18,2)
        );

        -- Populate the temporary table with filtered orders
        INSERT INTO #FilteredOrders
        SELECT O.OrderID, O.CustomerID, P.ProductID, O.Quantity, O.TotalAmount
        FROM Orders O
        JOIN Customers C ON O.CustomerID = C.CustomerID
        WHERE O.TotalAmount BETWEEN @MinOrderAmount AND @MaxOrderAmount;

        -- Select the required columns from the temporary table and order by TotalAmount ASC
        SELECT OrderID, CustomerID, ProductID, Quantity, TotalAmount
        FROM #FilteredOrders
        ORDER BY TotalAmount ASC;

        -- Drop the temporary table
        DROP TABLE #FilteredOrders;
    END TRY
    BEGIN CATCH
        DECLARE @ErrorMessage NVARCHAR(4000);
        SET @ErrorMessage = ERROR_MESSAGE();
        RAISERROR('An error occurred: %s', 16, 1, @ErrorMessage);
        RETURN;
    END CATCH
END

