CREATE PROCEDURE GetOrdersByCustomerID
    @CustomerID INT,
    @Status NVARCHAR(50)
AS
BEGIN
    DECLARE @OutputOrderID INT;

    BEGIN TRY
        MERGE INTO Orders AS T1
        USING (
            SELECT OrderID, CustomerID, Status
            FROM Orders
            WHERE CustomerID = @CustomerID AND Status = @Status
        ) AS T2
        ON T1.OrderID = T2.OrderID

        WHEN MATCHED THEN
            UPDATE SET Status = T2.Status
        WHEN NOT MATCHED THEN
            INSERT (OrderID, CustomerID, Status)
            VALUES (T2.OrderID, T2.CustomerID, T2.Status);

        SELECT @OutputOrderID = SCOPE_IDENTITY();
    END TRY

    BEGIN CATCH
        DECLARE @ErrorMessage NVARCHAR(4000);
        SET @ErrorMessage = ERROR_MESSAGE();

        RAISERROR(@ErrorMessage, 16, 1);
    END CATCH;

    RETURN @OutputOrderID;
END

