DECLARE
    TYPE category_path_table IS TABLE OF VARCHAR2(4000);
    v_category_id NUMBER := 1;
    v_category_path category_path_table;
BEGIN
    -- Open a cursor to fetch categories recursively
    FOR rec IN (
        SELECT category_name, parent_category_id
        FROM product_categories
        WHERE category_id = v_category_id
    ) LOOP
        -- Append the current category name to the path
        v_category_path.EXTEND;
        v_category_path(v_category_path.COUNT) := rec.category_name;

        -- Check if the depth exceeds 10 and exit if true
        IF v_category_path.COUNT > 10 THEN
            EXIT;
        END IF;

        -- Recursively fetch parent categories
        FOR rec_parent IN (
            SELECT category_id, category_name, parent_category_id
            FROM product_categories
            WHERE category_id = rec.parent_category_id
        ) LOOP
            -- Append the current parent category name to the path
            v_category_path.EXTEND;
            v_category_path(v_category_path.COUNT) := rec_parent.category_name;

            -- Check if the depth exceeds 10 and exit if true
            IF v_category_path.COUNT > 10 THEN
                EXIT;
            END IF;

            -- Fetch grandparent categories recursively
            FOR rec_grandparent IN (
                SELECT category_id, category_name, parent_category_id
                FROM product_categories
                WHERE category_id = rec_parent.parent_category_id
            ) LOOP
                -- Append the current grandparent category name to the path
                v_category_path.EXTEND;
                v_category_path(v_category_path.COUNT) := rec_grandparent.category_name;

                -- Check if the depth exceeds 10 and exit if true
                IF v_category_path.COUNT > 10 THEN
                    EXIT;
                END IF;

                -- Fetch great-grandparent categories recursively
                FOR rec_greatgrandparent IN (
                    SELECT category_id, category_name, parent_category_id
                    FROM product_categories
                    WHERE category_id = rec_grandparent.parent_category_id
                ) LOOP
                    -- Append the current great-grandparent category name to the path
                    v_category_path.EXTEND;
                    v_category_path(v_category_path.COUNT) := rec_greatgrandparent.category_name;

                    -- Check if the depth exceeds 10 and exit if true
                    IF v_category_path.COUNT > 10 THEN
                        EXIT;
                    END IF;
                END LOOP;
            END LOOP;
        END LOOP;
    END LOOP;

    -- Output the category path to DBMS_OUTPUT
    FOR i IN 1..v_category_path.COUNT LOOP
        DBMS_OUTPUT.PUT_LINE(v_category_path(i));
    END LOOP;
END get_product_category_path;
/

CREATE PROCEDURE UpdateCustomerOrders
AS
BEGIN
    DECLARE @CustomerId INT;
    DECLARE @OrderID INT;

    -- Start a cursor to iterate over customers
    DECLARE customer_cursor CURSOR FOR
        SELECT CustomerID FROM Customers WHERE Status = 'Active';

    OPEN customer_cursor;

    FETCH NEXT FROM customer_cursor INTO @CustomerId;

    WHILE @@FETCH_STATUS = 0
    BEGIN
        -- Start a TRY/CATCH block for handling errors during the merge operation
        BEGIN TRY
            -- Attempt to update orders for the current customer
            UPDATE Orders
            SET OrderStatus = 'Shipped'
            WHERE CustomerID = @CustomerId AND Status = 'Pending';

            -- Output the updated order details
            INSERT INTO UpdatedOrders (CustomerID, OrderID, OrderStatus)
            SELECT CustomerID, OrderID, OrderStatus FROM Orders WHERE CustomerID = @CustomerId AND Status = 'Shipped';
        END TRY

        BEGIN CATCH
            -- If an error occurs, output the error message and log it
            DECLARE @ErrorMessage NVARCHAR(4000);
            SET @ErrorMessage = ERROR_MESSAGE();

            PRINT 'Error occurred for customer ID: ' + CAST(@CustomerId AS VARCHAR(10)) + ', Order ID: ' + CAST(@OrderID AS VARCHAR(10));
            RAISERROR('An error occurred while processing order for customer ID: ' + CAST(@CustomerId AS VARCHAR(10)), 16, 1, @ErrorMessage);
        END CATCH

        -- Fetch the next customer from the cursor
        FETCH NEXT FROM customer_cursor INTO @CustomerId;
    END;

    CLOSE customer_cursor;
    DEALLOCATE customer_cursor;
END

CREATE PROCEDURE usp_UpdateInventory
    @ProductID INT,
    @NewQuantity INT,
    @MaxRetries INT = 3
AS
BEGIN
    SET NOCOUNT ON;
    DECLARE @Retries INT = 0;
    DECLARE @Success BIT = 0;

    WHILE @Retries < @MaxRetries AND @Success = 0
    BEGIN
        BEGIN TRY
            BEGIN TRANSACTION;

            -- Lock in consistent order to prevent deadlock
            DECLARE @MinId INT = CASE WHEN @ProductID < @NewQuantity THEN @ProductID ELSE @NewQuantity END;
            DECLARE @MaxId INT = CASE WHEN @ProductID < @NewQuantity THEN @NewQuantity ELSE @ProductID END;

            SELECT ProductID, Quantity
            INTO #TempInventory
            FROM Inventory WITH (UPDLOCK, ROWLOCK)
            WHERE ProductID IN (@MinId, @MaxId);

            IF (SELECT SUM(Quantity) FROM #TempInventory) < @NewQuantity
                RAISERROR('Insufficient inventory', 16, 1);

            UPDATE Inventory SET Quantity = Quantity - @NewQuantity WHERE ProductID = @ProductID;
            INSERT INTO Transactions (ProductID, NewQuantity, TransactionDate, Status)
            VALUES (@ProductID, @NewQuantity, GETDATE(), 'COMPLETED');

            COMMIT TRANSACTION;
            SET @Success = 1;
        END TRY
        BEGIN CATCH
            IF @@TRANCOUNT > 0 ROLLBACK TRANSACTION;
            IF ERROR_NUMBER() = 1205 -- Deadlock
            BEGIN
                SET @Retries = @Retries + 1;
                WAITFOR DELAY '00:00:00.1';
            END
            ELSE THROW;
        END CATCH
    END

    IF @Success = 0
        RAISERROR('Transaction failed after max retries', 16, 1);
END

