CREATE OR REPLACE PROCEDURE cascade_project_cancellation(cancelled_projects_df IN OUT TABLE) IS
    CURSOR task_cursor IS
        SELECT project_id, status FROM tasks WHERE project_id IN (SELECT project_id FROM cancelled_projects_df);
    v_task_count NUMBER;
    v_updated_count NUMBER := 0;
BEGIN
    BEGIN
        FOR task_rec IN task_cursor LOOP
            SELECT COUNT(*)
            INTO v_task_count
            FROM tasks
            WHERE project_id = task_rec.project_id
              AND status NOT IN ('COMPLETED', 'CANCELLED');

            IF v_task_count > 0 THEN
                UPDATE tasks
                SET status        = 'CANCELLED',
                    cancelled_at  = SYSDATE,
                    cancel_reason = 'Parent project cancelled'
                WHERE project_id  = task_rec.project_id
                  AND status NOT IN ('COMPLETED', 'CANCELLED');

                v_updated_count := SQL%ROWCOUNT;

                INSERT INTO project_audit (
                    audit_id, project_id, event_type, description,
                    old_status, new_status, event_date
                ) VALUES (
                    proj_audit_seq.NEXTVAL,
                    task_rec.project_id,
                    'CASCADE_CANCEL',
                    'Cancelled ' || v_updated_count || ' open tasks due to project cancellation',
                    task_rec.status,
                    'CANCELLED',
                    SYSDATE
                );
            END IF;
        END LOOP;

        -- Commit the transaction if all tasks are successfully updated
        COMMIT;
    EXCEPTION
        WHEN OTHERS THEN
            -- Rollback the transaction in case of an error
            ROLLBACK;
            RAISE;
    END;
END cascade_project_cancellation;

CREATE OR REPLACE PROCEDURE update_order_status(
  p_order_id IN NUMBER,
  p_status   OUT VARCHAR2
) AS
  v_sql     VARCHAR2(4000);
  v_table_name VARCHAR2(50);
BEGIN
  v_table_name := 'ORDERS';

  -- Open a cursor to fetch the order details
  OPEN c_orders FOR
    SELECT * FROM ORDERS WHERE ORDER_ID = p_order_id;

  -- Fetch all rows into a collection
  DECLARE TYPE ord_rec IS RECORD (
    order_id NUMBER,
    status VARCHAR2(50)
  );
  TYPE ord_tab IS TABLE OF ord_rec;
  v_ord_tab ord_tab;
BEGIN
  FETCH c_orders BULK COLLECT INTO v_ord_tab;
  CLOSE c_orders;

  -- Process each order in the collection
  FOR i IN 1..v_ord_tab.COUNT LOOP
    IF v_ord_tab(i).status = 'Pending' THEN
      v_sql := 'UPDATE ORDERS SET status = ''Shipped'' WHERE ORDER_ID = :order_id';
      EXECUTE IMMEDIATE v_sql USING v_ord_tab(i).order_id;
      COMMIT;
      p_status := 'STATUS UPDATED:' || v_ord_tab(i).order_id;
    ELSE
      p_status := 'OK';
    END IF;
  END LOOP;

EXCEPTION
  WHEN OTHERS THEN
    ROLLBACK;
    p_status := 'ERROR:' || SQLERRM;
END update_order_status;

