CREATE PROCEDURE GetProductSales
    @ProductId INT,
    @StartDate DATE,
    @EndDate DATE
AS
BEGIN
    DECLARE @TotalSales DECIMAL(10, 2) = 0;

    BEGIN TRY
        -- Create a temporary table to store the product sales for the specified period
        CREATE TABLE #TempProductSales (
            ProductID INT,
            SalesDate DATE,
            SalesAmount DECIMAL(10, 2)
        );

        -- Populate the temporary table with sales data within the specified date range
        INSERT INTO #TempProductSales (ProductID, SalesDate, SalesAmount)
        SELECT P.ProductID, OD.SalesDate, OD.UnitPrice * OD.Quantity AS SalesAmount
        FROM Products P
        JOIN Order Details OD ON P.ProductID = OD.ProductID
        WHERE OD.OrderDate BETWEEN @StartDate AND @EndDate;

        -- Perform a merge operation to update the total sales
        MERGE INTO ProductSales ps
        USING #TempProductSales tp
        ON ps.ProductID = tp.ProductID AND ps.SalesDate = tp.SalesDate
        WHEN MATCHED THEN
            UPDATE SET ps.TotalSales = ps.TotalSales + tp.SalesAmount
        WHEN NOT MATCHED BY TARGET THEN
            INSERT (ProductID, SalesDate, TotalSales) VALUES (tp.ProductID, tp.SalesDate, tp.SalesAmount);

        -- Clean up the temporary table
        DROP TABLE #TempProductSales;
    END TRY
    BEGIN CATCH
        DECLARE @ErrorMessage NVARCHAR(MAX);
        SET @ErrorMessage = ERROR_MESSAGE();

        RAISERROR('An error occurred: %s', 16, 1, @ErrorMessage) WITH LOG;

        -- Clean up the temporary table if an error occurs
        IF OBJECT_ID('#TempProductSales') IS NOT NULL
            DROP TABLE #TempProductSales;
    END CATCH

    -- Return the total sales for the specified product and date range
    SELECT TotalSales FROM ProductSales WHERE ProductID = @ProductId AND SalesDate BETWEEN @StartDate AND @EndDate;
END

