DECLARE
    CURSOR loan_cursor IS
        SELECT account_id, principal, annual_rate, term_years FROM loan_accounts;

    TYPE loan_rec_type IS RECORD (
        account_id NUMBER,
        principal NUMBER,
        annual_rate NUMBER,
        term_years NUMBER
    );

    TYPE loan_rec_tab IS TABLE OF loan_rec_type INDEX BY PLS_INTEGER;

    loan_rec_array loan_rec_tab;
BEGIN
    OPEN loan_cursor;

    LOOP
        FETCH loan_cursor INTO loan_rec_array(CURSOR%ROWNUM);

        EXIT WHEN loan_cursor%NOTFOUND;

        BEGIN
            DECLARE
                v_final_amount NUMBER;
            BEGIN
                v_final_amount := calculate_compound_interest(loan_rec_array(CURSOR%ROWNUM).principal, loan_rec_array(CURSOR%ROWNUM).annual_rate, loan_rec_array(CURSOR%ROWNUM).term_years);

                DBMS_OUTPUT.PUT_LINE('Account ID: ' || loan_rec_array(CURSOR%ROWNUM).account_id || ', Maturity Value: ' || v_final_amount);
            EXCEPTION
                WHEN OTHERS THEN
                    DBMS_OUTPUT.PUT_LINE('Error in compound interest calculation for account ' || loan_rec_array(CURSOR%ROWNUM).account_id || ': ' || SQLERRM);
            END;
        END;
    END LOOP;

    CLOSE loan_cursor;
END;

PROCEDURE calculate_compound_interest(
    p_principal     IN NUMBER,
    p_annual_rate   IN NUMBER,
    p_years         IN NUMBER
) IS
    v_rate_per_period NUMBER;
    v_total_periods   NUMBER;
    v_final_amount    NUMBER;
BEGIN
    IF p_principal <= 0 OR p_annual_rate < 0 OR p_years <= 0 THEN
        RAISE_APPLICATION_ERROR(-20010, 'Invalid input parameters');
    END IF;

    v_rate_per_period := p_annual_rate / 100 / p_years;
    v_total_periods   := p_years * p_compounds_per_year;
    v_final_amount    := p_principal * POWER(1 + v_rate_per_period, v_total_periods);

    RETURN ROUND(v_final_amount, 2);
END calculate_compound_interest;

