CREATE PROCEDURE UpdateOrderStatus
AS
BEGIN TRY
    -- Create a temporary table to hold the updated order details
    CREATE TABLE #UpdatedOrders (
        OrderID INT,
        CustomerID INT,
        ProductID INT,
        Quantity INT,
        Status VARCHAR(50)
    );

    -- Merge the new status into the existing orders
    MERGE INTO Orders AS T1
    USING #UpdatedOrders AS T2
    ON T1.OrderID = T2.OrderID
    WHEN MATCHED THEN
        UPDATE SET T1.Status = T2.Status;

    -- Clean up the temporary table
    DROP TABLE #UpdatedOrders;
END TRY
BEGIN CATCH
    -- Handle any errors that occur during the merge operation
    DECLARE @ErrorMessage NVARCHAR(MAX);
    SELECT @ErrorMessage = ERROR_MESSAGE();
    RAISERROR('An error occurred while updating order status: %s', 16, 1, @ErrorMessage) WITH NOWAIT;
END CATCH;

CREATE PROCEDURE RecalculateAccountBalance
    @AccountID INT,
    @StartingBalance DECIMAL(18,2),
    @NewBalance DECIMAL(18,2) OUTPUT,
    @TotalCredits DECIMAL(18,2) OUTPUT,
    @TotalDebits DECIMAL(18,2) OUTPUT,
    @TransactionCount INT OUTPUT,
    @HasOverdraft BIT OUTPUT
AS
BEGIN
    SET NOCOUNT ON;

    SELECT
        @TotalCredits = ISNULL(SUM(CASE WHEN TransactionType = 'CREDIT' THEN Amount ELSE 0 END), 0),
        @TotalDebits = ISNULL(SUM(CASE WHEN TransactionType = 'DEBIT' THEN Amount ELSE 0 END), 0),
        @TransactionCount = COUNT(TransactionID)
    FROM Transactions
    WHERE AccountID = @AccountID
      AND Status = 'POSTED'
      AND TransactionDate >= DATEADD(MONTH, -1, GETDATE());

    SET @NewBalance = @StartingBalance + @TotalCredits - @TotalDebits;

    IF @NewBalance < 0
        SET @HasOverdraft = 1;
    ELSE
        SET @HasOverdraft = 0;

    UPDATE Accounts
    SET CurrentBalance = @NewBalance,
        LastRecalculated = GETDATE()
    WHERE AccountID = @AccountID;
END

