CREATE OR REPLACE PROCEDURE get_department_salary_stats(
  p_department_id IN NUMBER,
  p_total_salary OUT NUMBER,
  p_emp_count OUT NUMBER
) IS
BEGIN
  -- Declare a cursor to fetch department salary data
  CURSOR c_department_salaries IS
    SELECT salary, COUNT(*) AS emp_count
    FROM employees
    WHERE department_id = p_department_id
    GROUP BY salary;

  -- Initialize variables to store the total salary and employee count
  v_total_salary := 0;
  v_emp_count := 0;

  -- Open the cursor
  OPEN c_department_salaries;

  -- Fetch all records into a collection
  LOOP
    FETCH c_department_salaries INTO v_salary, v_emp_count;
    EXIT WHEN c_department_salaries%NOTFOUND;

    -- Add salary to total and increment employee count
    v_total_salary := v_total_salary + v_salary;
    v_emp_count := v_emp_count + 1;
  END LOOP;

  -- Close the cursor
  CLOSE c_department_salaries;

  -- Return the calculated values
  p_total_salary := v_total_salary;
  p_emp_count := v_emp_count;
END get_department_salary_stats;
