CREATE PROCEDURE ValidateAndGetCustomerStatus
    @CustomerID INT,
    @StatusCode NVARCHAR(20) OUTPUT,
    @CreditLimit DECIMAL(18,2) OUTPUT,
    @IsEligible BIT OUTPUT,
    @Message NVARCHAR(500) OUTPUT
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @TotalOrders INT;
    DECLARE @TotalSpend DECIMAL(18,2);
    DECLARE @DaysSinceLastOrder INT;

    SELECT
        @TotalOrders = COUNT(o.OrderID),
        @TotalSpend = SUM(o.TotalAmount),
        @DaysSinceLastOrder = DATEDIFF(DAY, MAX(o.OrderDate), GETDATE())
    FROM Orders o
    WHERE o.CustomerID = @CustomerID
      AND o.Status = 'Completed';

    IF @TotalOrders IS NULL
    BEGIN
        SET @StatusCode = 'NEW';
        SET @CreditLimit = 500.00;
        SET @IsEligible = 0;
        SET @Message = 'New customer with no order history';
        RETURN;
    END

    IF @TotalSpend >= 50000 AND @DaysSinceLastOrder <= 90
    BEGIN
        SET @StatusCode = 'PLATINUM';
        SET @CreditLimit = 25000.00;
        SET @IsEligible = 1;
        SET @Message = 'Platinum customer eligible for premium benefits';
    END
    ELSE IF @TotalSpend >= 10000 AND @DaysSinceLastOrder <= 180
    BEGIN
        SET @StatusCode = 'GOLD';
        SET @CreditLimit = 10000.00;
        SET @IsEligible = 1;
        SET @Message = 'Gold customer eligible for standard benefits';
    END
    ELSE IF @TotalSpend >= 1000
    BEGIN
        SET @StatusCode = 'SILVER';
        SET @CreditLimit = 2500.00;
        SET @IsEligible = 1;
        SET @Message = 'Silver customer with basic benefits';
    END
    ELSE
    BEGIN
        SET @StatusCode = 'BRONZE';
        SET @CreditLimit = 500.00;
        SET @IsEligible = 0;
        SET @Message = 'Bronze customer does not meet eligibility threshold';
    END
END

CREATE PROCEDURE usp_MergeAndArchiveOrders
    @ArchiveBeforeDate DATE,
    @RowsArchived      INT OUTPUT
AS
BEGIN
    SET NOCOUNT ON;
    SET @RowsArchived = 0;

    DECLARE @BatchSize  INT = 10000;
    DECLARE @Rows       INT = 1;

    -- Create a temporary table to hold orders before archiving
    CREATE TEMPORARY TABLE #OrdersBeforeArchive AS
    SELECT order_id, customer_id, order_date, total_amount, GETDATE() AS archived_at
    FROM dbo.orders
    WHERE order_date < @ArchiveBeforeDate
      AND order_status = 'COMPLETED';

    -- MERGE statement to update and insert data
    BEGIN TRY
        DECLARE @CurrentBatchSize INT = 0;
        DECLARE @CurrentRows INT = 0;

        WHILE @CurrentRows > 0
        BEGIN
            SET @CurrentBatchSize = CASE WHEN @CurrentBatchSize + @BatchSize < @CurrentRows THEN @CurrentBatchSize ELSE @CurrentRows END;
            SET @CurrentRows = (SELECT COUNT(*) FROM #OrdersBeforeArchive WHERE order_id IN (
                SELECT order_id FROM #OrdersBeforeArchive
                WHERE archived_at >= CAST(GETDATE() AS DATE)
                  AND order_date < @ArchiveBeforeDate
            )) - @CurrentBatchSize;

            MERGE INTO archive.orders AS target
            USING #OrdersBeforeArchive AS source
            ON target.order_id = source.order_id
            WHEN MATCHED THEN
                UPDATE SET target.archived_at = source.archived_at, target.updated_at = GETDATE()
            WHEN NOT MATCHED THEN
                INSERT (order_id, customer_id, order_date, total_amount, archived_at)
                VALUES (source.order_id, source.customer_id, source.order_date, source.total_amount, source.archived_at);

            SET @RowsArchived = @RowsArchived + @CurrentBatchSize;
        END TRY
        BEGIN CATCH
            ROLLBACK TRANSACTION;
            THROW;
        END CATCH;
    END;

    -- Drop the temporary table after processing
    DROP TABLE #OrdersBeforeArchive;
END;

