    SET NOCOUNT ON;

    BEGIN TRY
        CREATE TABLE #temp_orders AS
        SELECT o.customer_id, o.order_date, o.quantity, i.product_name
        FROM dbo.Orders o
        JOIN dbo.Inventory i ON o.inventory_id = i.inventory_id
        WHERE o.order_date BETWEEN @StartDate AND @EndDate;

        MERGE INTO dbo.CustomerOrdersReport cr
        USING #temp_orders to
