CREATE OR REPLACE PROCEDURE get_dept_avg_salary(
  p_department_id IN NUMBER,
  p_avg_salary OUT NUMBER
) AS
BEGIN
  -- Declare a cursor to fetch department average salary
  CURSOR dept_avg_cursor IS
    SELECT AVG(salary) FROM employees WHERE department_id = p_department_id;

  -- Open the cursor
  OPEN dept_avg_cursor;

  -- Fetch the result using BULK COLLECT
  TYPE avg_salary_table IS TABLE OF NUMBER;
  v_avg_salary_table avg_salary_table;
  v_num_rows NUMBER := 0;

  LOOP
    FETCH dept_avg_cursor INTO v_avg_salary_table(v_num_rows);
    EXIT WHEN dept_avg_cursor%NOTFOUND;
    v_num_rows := v_num_rows + 1;
  END LOOP;

  -- Close the cursor
  CLOSE dept_avg_cursor;

  -- Check if any rows were fetched
  IF v_num_rows > 0 THEN
    -- Assign the average salary to the OUT parameter
    p_avg_salary := v_avg_salary_table(1);
  ELSE
    -- Raise an exception if no data is found
    RAISE NO_DATA_FOUND;
  END IF;

EXCEPTION
  WHEN OTHERS THEN
    -- Log the error message using DBMS_OUTPUT
    DBMS_OUTPUT.PUT_LINE('Error: ' || SQLERRM);

    -- Reraise the exception to propagate it up the call stack
    RAISE;
END get_dept_avg_salary;
/

