CREATE OR REPLACE PACKAGE emp_pkg AS
  PROCEDURE calc_bonus(p_emp_id IN NUMBER) RETURN NUMBER;
  PROCEDURE apply_bonuses(p_dept_id IN NUMBER);
END emp_pkg;

CREATE OR REPLACE PACKAGE BODY emp_pkg AS
  FUNCTION calc_bonus(p_emp_id IN NUMBER) RETURN NUMBER IS
    v_salary   NUMBER;
    v_job_id   VARCHAR2(20);
    v_bonus    NUMBER := 0;
  BEGIN
    SELECT salary, job_id INTO v_salary, v_job_id
    FROM employees WHERE emp_id = p_emp_id;
    IF v_job_id LIKE 'SA%' THEN
      v_bonus := v_salary * 0.20;
    ELSIF v_job_id LIKE 'IT%' THEN
      v_bonus := v_salary * 0.15;
    ELSE
      v_bonus := v_salary * 0.10;
    END IF;
    RETURN v_bonus;
  EXCEPTION
    WHEN NO_DATA_FOUND THEN RETURN 0;
  END calc_bonus;

  PROCEDURE apply_bonuses(p_dept_id IN NUMBER) AS
    CURSOR emp_cursor IS
      SELECT emp_id, salary, job_id FROM employees WHERE department_id = p_dept_id;
    TYPE emp_record_type IS RECORD (
      emp_id NUMBER,
      salary NUMBER,
      job_id VARCHAR2(20)
    );
    emp_records emp_record_type := emp_cursor%ROWTYPE;
    v_bonus_number NUMBER := 0;
  BEGIN
    FOR rec IN emp_cursor LOOP
      v_bonus_number := emp_pkg.calc_bonus(rec.emp_id);
      UPDATE employees SET bonus = v_bonus_number WHERE emp_id = rec.emp_id;
    END LOOP;
    COMMIT;
  END apply_bonuses;
END emp_pkg;

