CREATE PROCEDURE usp_UpdateCustomerOrders (
    @CustomerId INT,
    @OrderAmount DECIMAL(10,2)
)
AS
BEGIN
    SET NOCOUNT ON;

    -- Create a temporary table to hold the updated orders
    CREATE TABLE #UpdatedOrders (
        CustomerId INT,
        OrderID INT,
        OrderAmount DECIMAL(10,2),
        LastModified DATETIME
    );

    -- Insert new or update existing orders in the temporary table
    INSERT INTO #UpdatedOrders (CustomerId, OrderID, OrderAmount, LastModified)
    SELECT 
        o.CustomerId,
        o.OrderID,
        o.OrderAmount,
        GETDATE()
    FROM 
        Orders o
    WHERE 
        o.CustomerId = @CustomerId AND o.OrderID NOT IN (
            SELECT OrderID FROM #UpdatedOrders
        );

    -- Merge the updated orders into the main Orders table
    MERGE INTO Orders t
    USING #UpdatedOrders u ON t.CustomerId = u.CustomerId AND t.OrderID = u.OrderID
    WHEN MATCHED THEN
        UPDATE SET 
            t.OrderAmount = u.OrderAmount,
            t.LastModified = u.LastModified
    WHEN NOT MATCHED BY TARGET THEN
        INSERT (
            CustomerId, OrderID, OrderAmount, LastModified
        )
        VALUES (
            u.CustomerId, u.OrderID, u.OrderAmount, u.LastModified
        );

    -- Handle any errors that occur during the merge operation
    BEGIN TRY
        -- If an error occurs, roll back the transaction
        ROLLBACK TRANSACTION;
    END TRY
    BEGIN CATCH
        -- If an error occurs, log it and rethrow the exception
        DECLARE @ErrorMessage NVARCHAR(MAX);
        SET @ErrorMessage = ERROR_MESSAGE();
        RAISERROR('An error occurred while updating customer orders: %s', 16, 1, @ErrorMessage);

        -- Rollback the transaction
        ROLLBACK TRANSACTION;
    END CATCH;

    -- Drop the temporary table after processing
    DROP TABLE #UpdatedOrders;
END;

CREATE PROCEDURE usp_MigrateOrdersToNewSystem
    @OrderID INT,
    @CustomerID INT,
    @EmployeeID INT,
    @ShipName NVARCHAR(50),
    @ShipAddress NVARCHAR(100),
    @ShipCity NVARCHAR(50),
    @ShipRegion NVARCHAR(20),
    @ShipPostalCode NVARCHAR(10),
    @ShipCountry NVARCHAR(30)
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @OrderNumber INT;
    DECLARE @OrderDate DATETIME;
    DECLARE @Freight DECIMAL(10, 2);
    DECLARE @ShipVia INT;
    DECLARE @Status NVARCHAR(50);

    DECLARE order_cursor CURSOR FOR
        SELECT OrderID, OrderDate, Freight, ShipVia, Status
        FROM   Orders;

    OPEN order_cursor;
    FETCH NEXT FROM order_cursor INTO @OrderNumber, @OrderDate, @Freight, @ShipVia, @Status;

    WHILE @@FETCH_STATUS = 0
    BEGIN
        DECLARE @NewOrderId INT;
        DECLARE @NewOrderDate DATETIME;
        DECLARE @NewFreight DECIMAL(10, 2);
        DECLARE @NewShipVia INT;
        DECLARE @NewStatus NVARCHAR(50);

        BEGIN TRY
            -- Create a new order in the new system
            INSERT INTO NewOrders (OrderNumber, OrderDate, Freight, ShipVia, Status)
            VALUES (@OrderNumber, @OrderDate, @Freight, @ShipVia, @Status);

            -- Get the newly created order ID
            SELECT @NewOrderId = SCOPE_IDENTITY();

            -- Update the order in the new system with additional information
            UPDATE NewOrders
            SET CustomerID = @CustomerID,
                EmployeeID = @EmployeeID,
                ShipName = @ShipName,
                ShipAddress = @ShipAddress,
                ShipCity = @ShipCity,
                ShipRegion = @ShipRegion,
                ShipPostalCode = @ShipPostalCode,
                ShipCountry = @ShipCountry
            WHERE  OrderID = @NewOrderId;
        END TRY

        BEGIN CATCH
            -- Handle any errors that occur during the migration process
            DECLARE @ErrorMessage NVARCHAR(MAX);
            SET @ErrorMessage = ERROR_MESSAGE();

            PRINT 'Error migrating order ' + CAST(@OrderNumber AS NVARCHAR(10)) + ': ' + @ErrorMessage;

            -- Rollback the transaction if an error occurs
            ROLLBACK TRANSACTION;
        END CATCH

        FETCH NEXT FROM order_cursor INTO @OrderNumber, @OrderDate, @Freight, @ShipVia, @Status;
    END;

    CLOSE order_cursor;
    DEALLOCATE order_cursor;
END;

DECLARE
  CURSOR audit_cursor IS
    SELECT table_name, operation, row_id, old_value, new_value, changed_at, changed_by
    FROM audit_log
    WHERE table_name = p_table_name
      AND TRUNC(changed_at) >= p_from_date;

  TYPE audit_row_type IS RECORD (
    table_name VARCHAR2(100),
    operation VARCHAR2(50),
    row_id VARCHAR2(100),
    old_value CLOB,
    new_value CLOB,
    changed_at TIMESTAMP,
    changed_by VARCHAR2(100)
  );

  TYPE audit_rows_type IS TABLE OF audit_row_type;

  audit_rows audit_rows_type;
BEGIN
  OPEN audit_cursor;

  LOOP
    FETCH audit_cursor BULK COLLECT INTO audit_rows LIMIT 1000;

    FOR i IN audit_rows.FIRST..audit_rows.LAST LOOP
      BEGIN
        -- Write audit log independently.
        INSERT INTO audit_log (
          table_name, operation, row_id,
          old_value, new_value,
          changed_at, changed_by
        )
        VALUES (
          audit_rows(i).table_name, audit_rows(i).operation, audit_rows(i).row_id,
          audit_rows(i).old_value, audit_rows(i).new_value,
          audit_rows(i).changed_at, audit_rows(i).changed_by
        );
      EXCEPTION
        WHEN OTHERS THEN NULL;
      END;
    END LOOP;

    EXIT WHEN audit_cursor%NOTFOUND;
  END LOOP;

  CLOSE audit_cursor;
END log_change;

-- Exception handling to catch any errors during the process.
BEGIN
  BEGIN
    -- Call the procedure with some data.
    log_change('employees', 'INSERT', '12345');
  EXCEPTION
    WHEN OTHERS THEN
      DBMS_OUTPUT.PUT_LINE('An error occurred: ' || SQLERRM);
  END;
END;

