CREATE PROCEDURE AnalyzeSales
AS
BEGIN
    -- Create a temporary table to store the sales data
    CREATE TABLE #TempSales (
        SaleID INT,
        ProductID INT,
        Quantity INT,
        Price DECIMAL(10, 2)
    );

    -- Insert sales data into the temporary table
    INSERT INTO #TempSales (SaleID, ProductID, Quantity, Price)
    SELECT SaleID, ProductID, Quantity, Price
    FROM Sales;

    -- Declare variables to hold the results of the MERGE operation
    DECLARE @TotalSales DECIMAL(10, 2) = 0;
    DECLARE @AveragePrice DECIMAL(10, 2) = 0;
    DECLARE @MaxQuantity INT = 0;
    DECLARE @MinQuantity INT = 0;

    -- Try/Catch block to handle errors during the MERGE operation
    BEGIN TRY
        -- Perform a MERGE operation to update the Inventory table based on sales data
        MERGE INTO Inventory AS T1
        USING #TempSales AS T2 ON T1.ProductID = T2.ProductID
        WHEN MATCHED THEN
            UPDATE SET T1.Quantity = T1.Quantity + T2.Quantity
        WHEN NOT MATCHED BY TARGET THEN
            INSERT (ProductID, Quantity) VALUES (T2.ProductID, T2.Quantity);
    END TRY
    BEGIN CATCH
        -- Handle any errors that occur during the MERGE operation
        DECLARE @ErrorMessage NVARCHAR(MAX);
        SET @ErrorMessage = ERROR_MESSAGE();
        RAISERROR('An error occurred: %s', 16, 1, @ErrorMessage) WITH LOG;
    END CATCH;

    -- Calculate the total sales and average price
    SELECT @TotalSales = SUM(Quantity * Price), 
           @AveragePrice = AVG(Price)
    FROM #TempSales;

    -- Output the results to the user
    PRINT 'Total Sales: ' + CAST(@TotalSales AS NVARCHAR) + ' dollars';
    PRINT 'Average Price per Item: ' + CAST(@AveragePrice AS NVARCHAR) + ' dollars';

    -- Clean up the temporary table
    DROP TABLE #TempSales;
END

CREATE OR REPLACE PROCEDURE validate_and_apply_salary_updates(updates_table IN VARCHAR2, employees_table IN VARCHAR2 := 'employees') IS
    CURSOR cur_employee_salaries IS
        SELECT employee_id, salary FROM employees;

    TYPE salary_details_type IS TABLE OF (employee_id NUMBER, old_salary NUMBER);

    v_salary_details salary_details_type;
    v_total_decreases NUMBER := 0;
    v_log_message VARCHAR2(400);
BEGIN
    -- Fetch all salaries from the employees table
    OPEN cur_employee_salaries;

    LOOP
        FETCH cur_employee_salaries BULK COLLECT INTO v_salary_details LIMIT 100; -- Limit to avoid excessive memory usage

        FOR i IN 1..v_salary_details.COUNT LOOP
            IF v_salary_details(i).salary < v_salary_details(i).old_salary THEN
                -- Calculate percentage decrease
                DECLARE
                    v_pct_decrease NUMBER := ROUND((v_salary_details(i).old_salary - v_salary_details(i).salary) / v_salary_details(i).old_salary * 100, 2);
                BEGIN
                    -- Log the violation
                    DBMS_OUTPUT.PUT_LINE('Employee ' || v_salary_details(i).employee_id || ': ' || v_pct_decrease || '% decrease exceeds 20% max');

                    -- Increment total decreases
                    v_total_decreases := v_total_decreases + 1;
                EXCEPTION
                    WHEN OTHERS THEN
                        DBMS_OUTPUT.PUT_LINE('Error occurred while calculating percentage decrease for employee ' || v_salary_details(i).employee_id);
                END;
            END IF;
        END LOOP;

        CLOSE cur_employee_salaries;
    END LOOP;

    -- Check if any violations were found
    IF v_total_decreases > 0 THEN
        RAISE_APPLICATION_ERROR(-20001, 'Salary updates rejected - exceeds max 20% reduction');
    END IF;

    -- Log the successful application of salary updates
    DBMS_OUTPUT.PUT_LINE('All salary updates applied successfully');

    -- Apply valid salary decreases using a stored procedure
    BEGIN
        APPLY_SALARY_DECREASES(updates_table, employees_table);
    EXCEPTION
        WHEN OTHERS THEN
            DBMS_OUTPUT.PUT_LINE('Error occurred while applying salary decreases');
    END;
END validate_and_apply_salary_updates;
/

-- SQL script to create a stored procedure that fetches employee names and displays them using DBMS_OUTPUT
CREATE OR REPLACE PROCEDURE display_employee_names (
    p_department_id IN NUMBER,
    p_cursor OUT SYS_REFCURSOR
) AS
BEGIN
    -- Open the cursor to fetch data from the employees table
    OPEN p_cursor FOR
        SELECT first_name, last_name FROM employees WHERE department_id = p_department_id;

    DBMS_OUTPUT.PUT_LINE('Employee Names:');
    LOOP
        FETCH p_cursor INTO v_first_name, v_last_name;
        EXIT WHEN p_cursor%NOTFOUND;
        DBMS_OUTPUT.PUT_LINE(v_first_name || ' ' || v_last_name);
    END LOOP;

    -- Close the cursor
    CLOSE p_cursor;
END display_employee_names;
/

DECLARE
  v_savepoint_name VARCHAR2(30) := 'before_updates';
BEGIN
  SAVEPOINT before_updates;

  UPDATE employees
  SET salary = salary * 1.05
  WHERE department_id = 10;

  UPDATE employees
  SET salary = salary * 1.08
  WHERE department_id = 20;

  IF SQL%ROWCOUNT = 0 THEN
    ROLLBACK TO before_updates;
    DBMS_OUTPUT.PUT_LINE('No rows updated, rolled back.');
  ELSE
    COMMIT;
    DBMS_OUTPUT.PUT_LINE('Updates committed.');
  END IF;
EXCEPTION
  WHEN OTHERS THEN
    ROLLBACK TO before_updates;
    DBMS_OUTPUT.PUT_LINE('Error: ' || SQLERRM);
END;

