-- PL/SQL block with CURSOR, BULK COLLECT, EXCEPTION handling, DBMS_OUTPUT, stored procedures/functions
CREATE OR REPLACE PROCEDURE get_employee_info AS
  CURSOR emp_cursor IS
    SELECT emp_id, first_name, last_name, salary
    FROM employees
    WHERE department_id = 10;

  v_emp emp_cursor%ROWTYPE;
BEGIN
  -- Open the cursor
  OPEN emp_cursor;

  -- Declare a table to hold the results
  TYPE emp_table_type IS TABLE OF emp_cursor%ROWTYPE;
  emp_table emp_table_type;

  -- Collect all rows into the table
  BEGIN
    LOOP
      FETCH emp_cursor INTO v_emp;
      EXIT WHEN emp_cursor%NOTFOUND;

      -- Add the row to the table
      emp_table.EXTEND;
      emp_table(emp_table.COUNT) := v_emp;
    END LOOP;

    -- Close the cursor
    CLOSE emp_cursor;
  EXCEPTION
    WHEN OTHERS THEN
      DBMS_OUTPUT.PUT_LINE('An error occurred: ' || SQLERRM);
  END;

  -- Call a stored procedure to process the data
  CALL process_employee_info(emp_table);

END get_employee_info;
/
